window.SHADER_SOURCES["air-shader.glsl"] = "precision highp float;\r\n\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// AIR SHADER - Wind/Air Element Theme\r\n// Features: Flowing wind patterns, floating particles, swirling currents\r\n// Light, airy, ethereal feel with domain warping\r\n// ============================================================================\r\n\r\n// High-quality hash functions\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\n// Quintic interpolation\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\n// Smooth value noise\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = fract(p);\r\n    f = quintic(f);\r\n\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\n// Fractal Brownian Motion\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    float frequency = 1.0;\r\n\r\n    for(int i = 0; i < 8; i++) {\r\n        if(i >= octaves) break;\r\n        value += amplitude * valueNoise(p * frequency);\r\n        frequency *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Advanced domain warping for wind flow visualization\r\nvec2 domainWarp(vec2 p, float time, int depth) {\r\n    vec2 q = vec2(\r\n        fbm(p + vec2(0.0, 0.0), 4),\r\n        fbm(p + vec2(5.2, 1.3), 4)\r\n    );\r\n\r\n    if(depth < 2) {\r\n        vec2 r = vec2(\r\n            fbm(p + 4.0 * q + vec2(time * 0.05, time * 0.03), 3),\r\n            fbm(p + 4.0 * q + vec2(time * 0.04, -time * 0.06), 3)\r\n        );\r\n\r\n        if(depth < 1) {\r\n            return p + r * 1.5;\r\n        }\r\n        return p + q * 2.0 + r * 0.5;\r\n    }\r\n\r\n    return p + q * 1.0;\r\n}\r\n\r\n// Flowing wind patterns with turbulence\r\nfloat windFlow(vec2 uv, float time) {\r\n    // Create flowing wind using domain warping\r\n    vec2 p = uv * 4.0;\r\n\r\n    // Apply domain warping for realistic flow\r\n    vec2 warped = domainWarp(p, time, 1);\r\n\r\n    // Multi-scale wind patterns\r\n    float flow1 = fbm(warped + vec2(time * 0.08, 0.0), 5);\r\n    float flow2 = fbm(warped * 1.5 + vec2(-time * 0.06, time * 0.05), 4);\r\n    float flow3 = fbm(warped * 2.5 + vec2(time * 0.04, -time * 0.07), 3);\r\n\r\n    // Combine flows\r\n    float wind = flow1 * 0.5 + flow2 * 0.3 + flow3 * 0.2;\r\n\r\n    return wind;\r\n}\r\n\r\n// Swirling air currents (visible wind streams)\r\nfloat airCurrents(vec2 uv, float time) {\r\n    vec2 p = uv * 6.0;\r\n\r\n    // Create spiral/vortex patterns\r\n    vec2 center = vec2(0.5, 0.5);\r\n    vec2 toCenter = p - center * 6.0;\r\n    float dist = length(toCenter);\r\n    float angle = atan(toCenter.y, toCenter.x);\r\n\r\n    // Rotating currents\r\n    float current = sin(angle * 3.0 + dist * 2.0 - time * 0.3) * 0.5 + 0.5;\r\n    current *= sin(angle * 5.0 - dist * 1.5 + time * 0.4) * 0.5 + 0.5;\r\n\r\n    // Add noise variation\r\n    current *= fbm(p + vec2(time * 0.05, -time * 0.06), 3);\r\n\r\n    // Make currents more defined\r\n    current = smoothstep(0.3, 0.7, current);\r\n\r\n    // Fade with distance from spiral\r\n    current *= smoothstep(8.0, 2.0, dist);\r\n\r\n    return current;\r\n}\r\n\r\n// Floating particles (feathers/leaves) with wind-affected motion\r\nfloat floatingParticles(vec2 uv_scaled, float time) {\r\n    float particles = 0.0;\r\n\r\n    for(int i = 0; i < 12; i++) {\r\n        float fi = float(i);\r\n        float seed = hash12(vec2(fi, 0.0));\r\n\r\n        // Particle lifetime\r\n        float lifetime = 8.0 + seed * 4.0;\r\n        float t = mod(time * 0.06 + seed * lifetime, lifetime) / lifetime;\r\n\r\n        // Starting position\r\n        vec2 start_pos = vec2(\r\n            hash12(vec2(fi, 1.0)) * 2.5 - 1.25,\r\n            hash12(vec2(fi, 2.0)) * 2.5 - 1.25\r\n        );\r\n\r\n        // Wind-affected motion (flowing, swirling)\r\n        vec2 wind_offset = vec2(\r\n            fbm(vec2(fi, time * 0.1), 3) * 2.0 - 1.0,\r\n            fbm(vec2(fi + 10.0, time * 0.08), 3) * 2.0 - 1.0\r\n        );\r\n\r\n        // Spiral motion\r\n        float spiral_angle = t * 12.56 + fi * 2.0;\r\n        float spiral_radius = 0.3 * sin(time * 0.2 + fi);\r\n\r\n        vec2 spiral = vec2(\r\n            cos(spiral_angle) * spiral_radius,\r\n            sin(spiral_angle) * spiral_radius\r\n        );\r\n\r\n        // Combined motion\r\n        vec2 particle_pos = start_pos + wind_offset * t * 0.5 + spiral;\r\n\r\n        float dist = length(uv_scaled - particle_pos);\r\n\r\n        // Particle shape (elongated like feather/leaf)\r\n        float angle_to_particle = atan(uv_scaled.y - particle_pos.y, uv_scaled.x - particle_pos.x);\r\n        float rotation = time * 0.5 + fi * 6.28;\r\n        float shaped_dist = dist * (1.0 + 0.3 * sin(angle_to_particle + rotation));\r\n\r\n        float size = 0.012 + hash12(vec2(fi, 3.0)) * 0.018;\r\n\r\n        // Particle with soft glow\r\n        float core = smoothstep(size, size * 0.3, shaped_dist);\r\n        float glow = smoothstep(size * 2.5, 0.0, shaped_dist) * 0.5;\r\n\r\n        // Tumbling/rotating fade\r\n        float tumble = 0.7 + 0.3 * sin(time * 1.5 + fi * 3.0);\r\n\r\n        // Smooth fade in/out\r\n        float fade = sin(t * 3.14159) * tumble;\r\n\r\n        particles += (core + glow) * fade;\r\n    }\r\n\r\n    return particles;\r\n}\r\n\r\n// Atmospheric transparency effect\r\nfloat atmosphericDepth(vec2 uv, float time) {\r\n    // Very subtle atmospheric variation\r\n    float depth = fbm(uv * 5.0 + vec2(time * 0.02, time * 0.015), 4);\r\n    return depth * 0.04;\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    vec2 uv_scaled = uv * 2.0 - 1.0;\r\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\r\n\r\n    // Airy color palette (light blues, whites, transparency feel)\r\n    vec3 light_air = vec3(0.91, 0.96, 0.97);      // #E8F4F8 - Very light blue\r\n    vec3 mid_air = vec3(0.84, 0.92, 0.95);        // #D6EAF2 - Soft blue\r\n    vec3 deep_air = vec3(0.72, 0.85, 0.91);       // #B8D8E8 - Deeper blue\r\n    vec3 wind_highlight = vec3(0.95, 0.98, 1.00); // #F2FAFF - Almost white\r\n    vec3 particle_glow = vec3(0.88, 0.93, 0.96);  // #E0EDF5 - Soft glow\r\n\r\n    // Base gradient (subtle, top to bottom)\r\n    vec3 base_color = mix(light_air, mid_air, uv.y * 0.6);\r\n    base_color = mix(base_color, deep_air, pow(uv.y, 2.0) * 0.4);\r\n\r\n    // Wind flow patterns\r\n    float wind = windFlow(uv, u_time);\r\n\r\n    // Apply wind as subtle color variation\r\n    vec3 wind_color = mix(base_color, wind_highlight, wind * 0.15);\r\n\r\n    // Air currents (visible streams)\r\n    float currents = airCurrents(uv, u_time);\r\n    wind_color = mix(wind_color, wind_highlight, currents * 0.12);\r\n\r\n    // Floating particles\r\n    float particles = floatingParticles(uv_scaled, u_time);\r\n\r\n    // Atmospheric depth texture\r\n    float depth = atmosphericDepth(uv, u_time);\r\n\r\n    // Combine effects\r\n    vec3 color = wind_color;\r\n\r\n    // Add subtle depth variation\r\n    color += depth;\r\n\r\n    // Add floating particles with glow\r\n    color = mix(color, particle_glow, particles * 0.35);\r\n\r\n    // Very subtle radial transparency effect (lighter in center)\r\n    float radial = smoothstep(1.2, 0.0, length(uv_scaled));\r\n    color = mix(color, light_air, radial * 0.08);\r\n\r\n    // Ensure light, airy feel (no dark areas)\r\n    color = max(color, vec3(0.7)); // Minimum brightness\r\n\r\n    // Apply intensity control\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}\r\n";

window.SHADER_SOURCES["aurora-shader.glsl"] = "precision highp float;\r\n\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// AURORA BOREALIS SHADER\r\n// Northern lights with vibrant colors and flowing patterns\r\n// ============================================================================\r\n\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = fract(p);\r\n    f = quintic(f);\r\n\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    float frequency = 1.0;\r\n\r\n    for(int i = 0; i < 8; i++) {\r\n        if(i >= octaves) break;\r\n        value += amplitude * valueNoise(p * frequency);\r\n        frequency *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Flowing aurora curtains\r\nvec3 aurora(vec2 uv, float time) {\r\n    vec2 p = vec2(uv.x * 3.0, uv.y * 2.0);\r\n\r\n    // Multiple flowing layers\r\n    float wave1 = fbm(p + vec2(time * 0.12, time * 0.08), 5);\r\n    float wave2 = fbm(p * 1.5 - vec2(time * 0.1, time * 0.06), 5);\r\n    float wave3 = fbm(p * 0.7 + vec2(time * 0.15, -time * 0.05), 4);\r\n    float wave4 = fbm(p * 2.0 + vec2(-time * 0.08, time * 0.1), 4);\r\n\r\n    // Combine waves\r\n    float aurora_val = (wave1 + wave2 * 0.8 + wave3 * 0.6 + wave4 * 0.5) / 3.0;\r\n\r\n    // Vertical curtain structure\r\n    float curtains = sin(uv.x * 12.0 + wave1 * 5.0 + time * 0.3) * 0.5 + 0.5;\r\n    curtains = pow(curtains, 2.0);\r\n    aurora_val *= 0.5 + curtains * 0.5;\r\n\r\n    // Shape to upper portion of sky\r\n    aurora_val *= smoothstep(0.3, 0.6, uv.y);\r\n    aurora_val *= 1.0 - smoothstep(0.7, 1.0, uv.y);\r\n\r\n    // Enhance contrast\r\n    aurora_val = pow(aurora_val, 1.2);\r\n\r\n    // Vibrant aurora colors\r\n    vec3 green = vec3(0.2, 0.9, 0.4);      // Bright green\r\n    vec3 purple = vec3(0.7, 0.2, 0.9);     // Vivid purple\r\n    vec3 blue = vec3(0.2, 0.5, 1.0);       // Bright blue\r\n    vec3 pink = vec3(1.0, 0.3, 0.6);       // Pink highlights\r\n\r\n    // Color variation across aurora\r\n    vec3 aurora_color = mix(green, purple, wave2);\r\n    aurora_color = mix(aurora_color, blue, wave3 * 0.6);\r\n    aurora_color = mix(aurora_color, pink, wave4 * 0.3);\r\n\r\n    return aurora_color * aurora_val;\r\n}\r\n\r\n// Twinkling stars\r\nfloat stars(vec2 uv, float time) {\r\n    vec2 grid = uv * 100.0;\r\n    vec2 id = floor(grid);\r\n    vec2 local = fract(grid);\r\n\r\n    float star = 0.0;\r\n    float h = hash12(id);\r\n\r\n    if(h > 0.95) {\r\n        vec2 star_pos = vec2(0.5);\r\n        float dist = length(local - star_pos);\r\n        float twinkle = 0.5 + 0.5 * sin(time * 3.0 + h * 6.28);\r\n        star = smoothstep(0.004, 0.0, dist) * twinkle;\r\n    }\r\n\r\n    return star;\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    vec2 uv_scaled = uv * 2.0 - 1.0;\r\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\r\n\r\n    // Dark night sky gradient\r\n    vec3 deep_night = vec3(0.02, 0.02, 0.08);    // #050515\r\n    vec3 horizon = vec3(0.05, 0.08, 0.15);       // #0d1426\r\n    vec3 sky_color = mix(horizon, deep_night, smoothstep(0.0, 0.5, uv.y));\r\n\r\n    // Stars\r\n    float star_val = stars(uv_scaled, u_time);\r\n    star_val += stars(uv_scaled * 1.3, u_time * 0.7) * 0.6;\r\n    vec3 star_color = vec3(0.9, 0.95, 1.0) * star_val;\r\n\r\n    // Aurora\r\n    vec3 aurora_color = aurora(uv, u_time);\r\n\r\n    // Add subtle glow around aurora\r\n    float glow = aurora(uv * 0.95, u_time * 1.1).g * 0.3;\r\n    sky_color += vec3(0.1, 0.2, 0.15) * glow;\r\n\r\n    // Combine\r\n    vec3 color = sky_color;\r\n    color += star_color;\r\n    color += aurora_color;\r\n\r\n    // Apply intensity\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}\r\n";

window.SHADER_SOURCES["chaos-shader.glsl"] = "precision highp float;\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// INTERSTELLAR BLACK HOLE SHADER - Gravitational lensing, accretion disk\r\n// Features: Einstein ring, multi-band disk, nebula warp, relativistic jets\r\n// ============================================================================\r\n\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = quintic(fract(p));\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    for (int i = 0; i < 8; i++) {\r\n        if (i >= octaves) break;\r\n        value += amplitude * valueNoise(p);\r\n        p *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Gravitational lensing: bends coordinates around black hole\r\nvec2 gravitationalLens(vec2 pos, float mass) {\r\n    float r = length(pos);\r\n    if (r < 0.001) return pos;\r\n    // Schwarzschild-inspired bending: stronger near singularity\r\n    float bend = mass / (r * r + mass * 0.3);\r\n    vec2 deflected = pos + normalize(pos) * (-bend) * r;\r\n    return deflected;\r\n}\r\n\r\n// Star field with gravitational distortion\r\nfloat starField(vec2 uv, float layer, float time) {\r\n    vec2 grid = uv * (90.0 + layer * 60.0);\r\n    vec2 id = floor(grid);\r\n    vec2 local = fract(grid);\r\n    float h = hash12(id + layer * 77.0);\r\n    if (h < 0.88) return 0.0;\r\n    vec2 starPos = vec2(0.5) + (hash22(id + layer * 77.0) - 0.5) * 0.85;\r\n    float dist = length(local - starPos);\r\n    float sz = 0.001 + hash12(id + layer * 77.0 + 5.0) * 0.003;\r\n    float twinkle = 0.5 + 0.5 * sin(time * (1.5 + h * 3.0) + h * 6.28);\r\n    return smoothstep(sz, 0.0, dist) * twinkle;\r\n}\r\n\r\n// Background nebula that gets warped\r\nvec3 backgroundNebula(vec2 uv, float time) {\r\n    vec2 p = uv * 1.8;\r\n    float n1 = fbm(p + vec2(time * 0.008, time * 0.005), 5);\r\n    float n2 = fbm(p * 1.4 - vec2(time * 0.006, time * 0.007), 4);\r\n    float n3 = fbm(p * 0.6 + vec2(-time * 0.004, time * 0.003), 3);\r\n    float nval = (n1 * 0.5 + n2 * 0.35 + n3 * 0.15);\r\n    nval = pow(nval, 2.2);\r\n    vec3 nebulaBlue   = vec3(0.02, 0.04, 0.14);\r\n    vec3 nebulaPurple = vec3(0.06, 0.02, 0.12);\r\n    vec3 nebulaRed    = vec3(0.08, 0.01, 0.04);\r\n    vec3 col = mix(nebulaBlue, nebulaPurple, n2);\r\n    col = mix(col, nebulaRed, n3 * 0.4);\r\n    return col * nval * 0.5;\r\n}\r\n\r\n// Accretion disk with temperature gradient bands\r\nvec3 accretionDisk(vec2 warped, float r, float angle, float time) {\r\n    // Disk plane flatness\r\n    float diskPlane = abs(warped.y) / (length(warped) + 0.001);\r\n    float flatness  = smoothstep(0.04, 0.0, diskPlane);\r\n\r\n    // Disk radial extent — inner hot, mid warm, outer cool\r\n    float diskMask = smoothstep(0.10, 0.18, r) * smoothstep(1.4, 0.5, r);\r\n\r\n    if (flatness < 0.001 || diskMask < 0.001) return vec3(0.0);\r\n\r\n    // Rotation (prograde) — material orbits inward faster at smaller r\r\n    float orbitalSpeed = 0.25 / (r + 0.05);\r\n    float phi = angle - time * orbitalSpeed;\r\n\r\n    // Turbulence in disk\r\n    float diskNoise = fbm(vec2(phi * 2.0, log(r + 0.01) * 5.0) + time * 0.03, 4);\r\n    float diskNoise2 = fbm(vec2(phi * 3.5 + 1.7, r * 8.0) - time * 0.05, 3);\r\n    float turbulence = 0.6 + 0.4 * diskNoise;\r\n\r\n    // Doppler boosting: approaching side (left) brighter\r\n    float doppler = 0.5 + 0.5 * sin(phi + 1.57);\r\n    float dopBoost = pow(max(0.0, doppler), 2.5) * 0.7 + 0.3;\r\n\r\n    // Temperature bands by radius\r\n    vec3 innerColor  = vec3(1.0, 0.98, 0.92);  // White-hot core\r\n    vec3 midColor    = vec3(1.0, 0.62, 0.12);  // Orange mid\r\n    vec3 outerColor  = vec3(0.6, 0.05, 0.0);   // Deep red outer\r\n\r\n    float t = smoothstep(0.10, 0.25, r);\r\n    float t2 = smoothstep(0.25, 0.65, r);\r\n    vec3 diskTemp = mix(innerColor, midColor, t);\r\n    diskTemp = mix(diskTemp, outerColor, t2);\r\n\r\n    float brightness = flatness * diskMask * turbulence * dopBoost;\r\n    brightness += flatness * diskMask * diskNoise2 * 0.25;\r\n\r\n    return diskTemp * brightness * 0.65;\r\n}\r\n\r\n// Relativistic jets: subtle glow above and below\r\nfloat jetGlow(vec2 pos, float r) {\r\n    // Jets along vertical axis (polar)\r\n    float jetWidth = 0.04;\r\n    float axialDist = abs(pos.x);\r\n    float jetMask = smoothstep(jetWidth, 0.0, axialDist);\r\n    // Only far from disk plane\r\n    float jetVertical = smoothstep(0.1, 0.4, abs(pos.y));\r\n    float jetFade = smoothstep(1.5, 0.3, abs(pos.y));\r\n    return jetMask * jetVertical * jetFade;\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    float aspect = u_resolution.x / u_resolution.y;\r\n    vec2 c = uv * 2.0 - 1.0;\r\n    c.x *= aspect;\r\n\r\n    float r = length(c);\r\n    float angle = atan(c.y, c.x);\r\n\r\n    // ── Gravitational lensing ─────────────────────────────────────────────\r\n    // Warp coordinate space — stronger near center\r\n    float mass = 0.22;\r\n    vec2 lensed = gravitationalLens(c, mass);\r\n    float lr = length(lensed);\r\n\r\n    // Einstein ring: photon sphere causes ring of light\r\n    float photonR = 0.15;\r\n    float einsteinRing = exp(-pow((r - photonR * 1.4) / 0.015, 2.0));\r\n    einsteinRing *= 0.6 + 0.4 * fbm(vec2(angle * 3.0, u_time * 0.1), 2);\r\n\r\n    // ── Star field behind, distorted by gravity ───────────────────────────\r\n    // Use lensed coordinates for stars so gravity bends their positions\r\n    float stars = 0.0;\r\n    stars += starField(lensed * 0.5, 0.0, u_time * 0.5) * 0.9;\r\n    stars += starField(lensed * 0.7, 1.0, u_time * 0.4) * 0.6;\r\n    stars += starField(lensed * 0.9, 2.0, u_time * 0.3) * 0.4;\r\n    // Stars dim near event horizon (photon capture)\r\n    stars *= smoothstep(0.11, 0.25, r);\r\n    vec3 starColor = vec3(0.9, 0.93, 1.0) * stars;\r\n\r\n    // ── Background nebula warped ──────────────────────────────────────────\r\n    vec3 nebula = backgroundNebula(lensed * 0.6 + 0.5, u_time);\r\n\r\n    // ── Accretion disk ────────────────────────────────────────────────────\r\n    // Additional spiral domain warp for smoky appearance\r\n    float spiral = angle + log(r + 0.001) * 2.5 - u_time * 0.12;\r\n    vec2 diskUV = vec2(spiral, r);\r\n    vec2 diskWarp = vec2(\r\n        fbm(diskUV * vec2(0.8, 3.0) + u_time * 0.04, 4),\r\n        fbm(diskUV * vec2(1.2, 4.0) - u_time * 0.03, 3)\r\n    );\r\n    vec2 warpedPos = c + diskWarp * 0.04;\r\n\r\n    vec3 disk = accretionDisk(warpedPos, length(warpedPos), atan(warpedPos.y, warpedPos.x), u_time);\r\n\r\n    // ── Smoky in-fall material ────────────────────────────────────────────\r\n    float infall1 = fbm(vec2(spiral * 0.7, r * 5.0) + u_time * 0.06, 5);\r\n    float infall2 = fbm(vec2(spiral * 1.3 + 3.0, r * 4.0) - u_time * 0.04, 4);\r\n    infall1 *= smoothstep(0.12, 0.35, r) * smoothstep(1.8, 0.4, r);\r\n    infall2 *= smoothstep(0.16, 0.45, r) * smoothstep(2.0, 0.5, r);\r\n    vec3 smokeColor = mix(vec3(0.45, 0.02, 0.0), vec3(0.9, 0.55, 0.0), infall1);\r\n    vec3 smoke = smokeColor * infall1 * 0.18 + mix(vec3(0.4, 0.0, 0.0), vec3(0.8, 0.5, 0.0), infall2) * infall2 * 0.10;\r\n\r\n    // ── Relativistic jets ─────────────────────────────────────────────────\r\n    float jet = jetGlow(c, r);\r\n    vec3 jetColor = vec3(0.3, 0.5, 1.0) * jet * 0.12;\r\n\r\n    // ── Event horizon shadow ──────────────────────────────────────────────\r\n    float horizon = 0.09;\r\n    float shadow = smoothstep(horizon, horizon + 0.08, r);\r\n    // Time dilation: smooth slowdown of animations near center\r\n    float timeDilationMask = smoothstep(0.0, 0.35, r);\r\n\r\n    // ── Background deep space ─────────────────────────────────────────────\r\n    vec3 deepSpace = vec3(0.005, 0.005, 0.015);\r\n\r\n    // ── Compose ──────────────────────────────────────────────────────────\r\n    vec3 color = deepSpace;\r\n    color += nebula;\r\n    color += starColor;\r\n    color += smoke;\r\n    color += disk;\r\n    color += vec3(1.0, 0.7, 0.3) * einsteinRing * 0.4;\r\n    color += jetColor;\r\n    color *= shadow;\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}";

window.SHADER_SOURCES["cosmic-shader.glsl"] = "precision highp float;\r\n\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// COSMIC SHADER\r\n// Deep space nebula with stars and cosmic dust\r\n// ============================================================================\r\n\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = fract(p);\r\n    f = quintic(f);\r\n\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    float frequency = 1.0;\r\n\r\n    for(int i = 0; i < 8; i++) {\r\n        if(i >= octaves) break;\r\n        value += amplitude * valueNoise(p * frequency);\r\n        frequency *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Nebula clouds\r\nvec3 nebula(vec2 uv, float time) {\r\n    vec2 p = uv * 2.5;\r\n\r\n    // Multiple nebula layers\r\n    float n1 = fbm(p + vec2(time * 0.015, time * 0.01), 6);\r\n    float n2 = fbm(p * 1.3 - vec2(time * 0.012, time * 0.008), 5);\r\n    float n3 = fbm(p * 0.8 + vec2(time * 0.018, -time * 0.01), 5);\r\n\r\n    // Combine for swirling effect\r\n    float nebula_val = (n1 * 0.6 + n2 * 0.4 + n3 * 0.3);\r\n    nebula_val = pow(nebula_val, 1.3);\r\n\r\n    // Add bright spots\r\n    float bright_spots = fbm(p * 3.0 + time * 0.02, 4);\r\n    bright_spots = pow(bright_spots, 3.0) * 0.5;\r\n    nebula_val += bright_spots;\r\n\r\n    // Cosmic nebula colors\r\n    vec3 purple = vec3(0.4, 0.1, 0.6);     // Deep purple\r\n    vec3 blue = vec3(0.1, 0.3, 0.8);       // Cosmic blue\r\n    vec3 pink = vec3(0.8, 0.2, 0.5);       // Pink highlights\r\n    vec3 cyan = vec3(0.2, 0.6, 0.8);       // Cyan accents\r\n\r\n    // Color variation across nebula\r\n    vec3 nebula_color = mix(purple, blue, n2);\r\n    nebula_color = mix(nebula_color, pink, n3 * 0.6);\r\n    nebula_color = mix(nebula_color, cyan, bright_spots);\r\n\r\n    return nebula_color * nebula_val * 0.8;\r\n}\r\n\r\n// Stars with varying sizes and colors\r\nfloat stars(vec2 uv, float layer, float time) {\r\n    vec2 grid = uv * (80.0 + layer * 60.0);\r\n    vec2 id = floor(grid);\r\n    vec2 local = fract(grid);\r\n\r\n    float star = 0.0;\r\n    float h = hash12(id + layer * 100.0);\r\n\r\n    if(h > 0.88) {\r\n        vec2 star_pos = vec2(0.5) + (hash22(id + layer * 100.0) - 0.5) * 0.9;\r\n        float dist = length(local - star_pos);\r\n\r\n        // Varied star sizes\r\n        float size = 0.001 + h * 0.005;\r\n\r\n        // Twinkling\r\n        float twinkle = 0.6 + 0.4 * sin(time * (2.0 + h * 3.0) + h * 6.28);\r\n\r\n        // Star brightness\r\n        star = smoothstep(size, 0.0, dist) * twinkle;\r\n\r\n        // Add glow for larger stars\r\n        if(h > 0.95) {\r\n            star += smoothstep(size * 3.0, 0.0, dist) * 0.3;\r\n        }\r\n    }\r\n\r\n    return star;\r\n}\r\n\r\n// Cosmic dust\r\nvec3 cosmicDust(vec2 uv, float time) {\r\n    vec2 p = uv * 4.0;\r\n\r\n    float dust1 = fbm(p + vec2(time * 0.01, time * 0.008), 5);\r\n    float dust2 = fbm(p * 1.5 - vec2(time * 0.012, -time * 0.006), 4);\r\n\r\n    float dust_val = (dust1 * 0.5 + dust2 * 0.5);\r\n    dust_val = pow(dust_val, 2.5) * 0.4;\r\n\r\n    // Dust colors (subtle greys and blues)\r\n    vec3 dust_color = vec3(0.15, 0.2, 0.3);\r\n\r\n    return dust_color * dust_val;\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    vec2 uv_scaled = uv * 2.0 - 1.0;\r\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\r\n\r\n    // Deep space gradient\r\n    vec3 deep_space = vec3(0.01, 0.01, 0.04);    // Nearly black\r\n    vec3 space_blue = vec3(0.03, 0.05, 0.12);    // Dark blue\r\n    vec3 space_color = mix(deep_space, space_blue, smoothstep(0.0, 0.5, uv.y));\r\n\r\n    // Stars - multiple layers for depth\r\n    float star_val = 0.0;\r\n    star_val += stars(uv_scaled, 0.0, u_time) * 1.0;\r\n    star_val += stars(uv_scaled, 1.0, u_time * 0.8) * 0.7;\r\n    star_val += stars(uv_scaled, 2.0, u_time * 0.6) * 0.5;\r\n    star_val += stars(uv_scaled, 3.0, u_time * 0.9) * 0.8;\r\n\r\n    // Star colors (slight color variation)\r\n    vec3 star_color = vec3(0.9, 0.95, 1.0) * star_val;\r\n\r\n    // Nebula\r\n    vec3 nebula_color = nebula(uv, u_time);\r\n\r\n    // Cosmic dust\r\n    vec3 dust_color = cosmicDust(uv, u_time);\r\n\r\n    // Combine all elements\r\n    vec3 color = space_color;\r\n    color += dust_color;\r\n    color += nebula_color;\r\n    color += star_color;\r\n\r\n    // Subtle vignette for depth\r\n    float vignette = 1.0 - 0.3 * length(uv_scaled * 0.5);\r\n    color *= vignette;\r\n\r\n    // Apply intensity\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}\r\n";

window.SHADER_SOURCES["dark-shader.glsl"] = "precision highp float;\n\nuniform vec2 u_resolution;\nuniform float u_time;\nuniform float u_intensity;\n\n// ============================================================================\n// PRODUCTION DARK SHADER - ShaderToy Inspired\n// Features: Flowing shadows, wispy particles, void/cosmic effect, parallax depth\n// ============================================================================\n\n// High-quality hash functions\nfloat hash12(vec2 p) {\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\n    p3 += dot(p3, p3.yzx + 33.33);\n    return fract((p3.x + p3.y) * p3.z);\n}\n\nvec2 hash22(vec2 p) {\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\n    p3 += dot(p3, p3.yzx + 33.33);\n    return fract((p3.xx + p3.yz) * p3.zy);\n}\n\n// Quintic interpolation\nvec2 quintic(vec2 t) {\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\n}\n\n// Smooth value noise\nfloat valueNoise(vec2 p) {\n    vec2 i = floor(p);\n    vec2 f = fract(p);\n    f = quintic(f);\n\n    float a = hash12(i);\n    float b = hash12(i + vec2(1.0, 0.0));\n    float c = hash12(i + vec2(0.0, 1.0));\n    float d = hash12(i + vec2(1.0, 1.0));\n\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\n}\n\n// FBM for organic shadow patterns\nfloat fbm(vec2 p, int octaves) {\n    float value = 0.0;\n    float amplitude = 0.5;\n    float frequency = 1.0;\n\n    for(int i = 0; i < 8; i++) {\n        if(i >= octaves) break;\n        value += amplitude * valueNoise(p * frequency);\n        frequency *= 2.0;\n        amplitude *= 0.5;\n    }\n    return value;\n}\n\n// Domain-warped flowing shadows\nfloat flowingShadows(vec2 uv, float time) {\n    vec2 p = uv * 4.0;\n\n    // Create flowing motion with domain warping\n    vec2 warp1 = vec2(\n        fbm(p + vec2(time * 0.05, 0.0), 3),\n        fbm(p + vec2(0.0, time * 0.06), 3)\n    );\n\n    vec2 warp2 = vec2(\n        fbm(p + warp1 * 2.0 + vec2(time * 0.03, 0.0), 4),\n        fbm(p + warp1 * 2.0 + vec2(0.0, time * 0.04), 4)\n    );\n\n    // Final shadow pattern\n    float shadows = fbm(p + warp2 * 3.0, 5);\n\n    return shadows;\n}\n\n// Wispy dark particles with smooth movement\nfloat wispyParticles(vec2 uv_scaled, float time) {\n    float particles = 0.0;\n\n    for(int i = 0; i < 15; i++) {\n        float fi = float(i);\n        float seed = hash12(vec2(fi, 0.0));\n\n        // Long lifetime for slow, smooth movement\n        float lifetime = 6.0 + seed * 4.0;\n        float t = mod(time * 0.06 + seed * lifetime, lifetime) / lifetime;\n\n        // Starting position\n        vec2 start_pos = vec2(\n            hash12(vec2(fi, 1.0)) * 2.0 - 1.0,\n            -0.8\n        );\n\n        // Smooth sine wave drift\n        float drift_x = sin(time * 0.2 + fi * 2.0) * 0.4;\n        float drift_y = t * 2.8;\n\n        // Add turbulence\n        drift_x += fbm(vec2(fi, time * 0.1), 2) * 0.3;\n\n        vec2 particle_pos = start_pos + vec2(drift_x, drift_y);\n\n        float dist = length(uv_scaled - particle_pos);\n        float size = 0.02 + hash12(vec2(fi, 2.0)) * 0.04;\n\n        // Wispy particle (very soft, elongated)\n        float wisp = smoothstep(size * 2.0, 0.0, dist);\n\n        // Add elongated tail\n        float tail_offset = sin(time * 0.5 + fi) * 0.1;\n        float tail_dist = length(uv_scaled - particle_pos - vec2(tail_offset, -0.2));\n        wisp += smoothstep(size * 3.0, 0.0, tail_dist) * 0.5;\n\n        // Smooth fade in/out\n        float fade = sin(t * 3.14159);\n        fade = pow(fade, 0.7);\n\n        particles += wisp * fade;\n    }\n\n    return particles;\n}\n\n// Dimmed star field for background depth\nfloat dimStars(vec2 uv, float layer) {\n    vec2 grid = uv * (80.0 + layer * 60.0);\n    vec2 id = floor(grid);\n    vec2 local = fract(grid);\n\n    float star = 0.0;\n    float h = hash12(id + layer * 50.0);\n\n    // Very sparse stars\n    if(h > 0.96) {\n        vec2 star_pos = vec2(0.5) + (hash22(id + layer * 50.0) - 0.5) * 0.9;\n        float dist = length(local - star_pos);\n        float size = 0.001 + h * 0.002;\n\n        // Very subtle twinkle\n        float twinkle = 0.6 + 0.4 * sin(u_time * 1.5 + h * 6.28);\n\n        star = smoothstep(size, 0.0, dist) * twinkle;\n    }\n\n    return star;\n}\n\n// Void/cosmic depth effect with parallax\nvec3 voidEffect(vec2 uv, float time) {\n    // Multiple parallax layers for depth\n    float layer1 = flowingShadows(uv * 0.8 + time * 0.02, time);\n    float layer2 = flowingShadows(uv * 1.2 - time * 0.015, time);\n    float layer3 = flowingShadows(uv * 1.6 + time * 0.01, time);\n\n    // Combine layers with different intensities\n    float combined = layer1 * 0.5 + layer2 * 0.3 + layer3 * 0.2;\n\n    // Dark purple tint for void effect\n    vec3 void_color = vec3(0.08, 0.06, 0.12);\n\n    return void_color * combined;\n}\n\nvoid main() {\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\n    vec2 uv_scaled = uv * 2.0 - 1.0;\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\n\n    // Very dark palette with purple tints\n    vec3 deep_dark = vec3(0.02, 0.02, 0.04);       // #05050a\n    vec3 mid_dark = vec3(0.04, 0.04, 0.06);        // #0a0a0f\n    vec3 light_dark = vec3(0.1, 0.1, 0.18);        // #1a1a2e\n    vec3 purple_tint = vec3(0.12, 0.08, 0.15);\n\n    // Base gradient\n    vec3 base_color = mix(deep_dark, mid_dark, smoothstep(0.0, 0.6, uv.y));\n    base_color = mix(base_color, light_dark, smoothstep(0.7, 1.0, uv.y));\n\n    // Void effect with parallax\n    vec3 void_val = voidEffect(uv, u_time);\n\n    // Flowing shadow patterns\n    float shadows = flowingShadows(uv, u_time);\n    vec3 shadow_color = mid_dark * smoothstep(0.3, 0.7, shadows);\n\n    // Wispy dark particles\n    float particles = wispyParticles(uv_scaled, u_time);\n    vec3 particle_color = purple_tint * particles;\n\n    // Dimmed background stars (very subtle)\n    float stars = 0.0;\n    stars += dimStars(uv_scaled, 0.0) * 0.3;\n    stars += dimStars(uv_scaled, 1.0) * 0.2;\n    vec3 star_color = vec3(0.15, 0.12, 0.18) * stars;\n\n    // Strong vignette for depth\n    float vignette = smoothstep(1.5, 0.3, length(uv_scaled));\n    vignette = pow(vignette, 0.8);\n\n    // Combine all elements\n    vec3 color = base_color;\n    color += void_val * 0.6;\n    color += shadow_color * 0.4;\n    color += particle_color * 0.3;\n    color += star_color;\n\n    // Apply vignette\n    color *= 0.5 + 0.5 * vignette;\n\n    // Apply intensity control\n    color *= u_intensity;\n\n    gl_FragColor = vec4(color, 1.0);\n}\n";

window.SHADER_SOURCES["day-shader.glsl"] = "precision highp float;\r\n\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// DAY SHADER - Bright Daylight Sky Theme\r\n// Features: Blue sky gradient, wispy clouds, subtle sun rays, warm atmosphere\r\n// Optimized for 60fps performance\r\n// ============================================================================\r\n\r\n// High-quality hash for randomness\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\n// Quintic interpolation for smooth transitions\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\n// Smooth value noise\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = fract(p);\r\n    f = quintic(f);\r\n\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\n// Fractal Brownian Motion for cloud patterns\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    float frequency = 1.0;\r\n\r\n    for(int i = 0; i < 8; i++) {\r\n        if(i >= octaves) break;\r\n        value += amplitude * valueNoise(p * frequency);\r\n        frequency *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Wispy, realistic cloud patterns using domain warping\r\nfloat clouds(vec2 uv, float time) {\r\n    // Multiple layers of clouds at different scales\r\n    vec2 p = uv * 3.0;\r\n\r\n    // Slow horizontal drift\r\n    p.x += time * 0.015;\r\n\r\n    // Domain warping for realistic cloud shapes\r\n    vec2 warp = vec2(\r\n        fbm(p + vec2(time * 0.01, 0.0), 3),\r\n        fbm(p + vec2(0.0, time * 0.012), 3)\r\n    );\r\n\r\n    // Primary cloud layer\r\n    float cloud1 = fbm(p + warp * 1.2, 5);\r\n\r\n    // Secondary wispy layer\r\n    float cloud2 = fbm(p * 1.8 + warp * 0.8 + vec2(time * 0.02, 0.0), 4);\r\n\r\n    // Combine layers\r\n    float cloud = cloud1 * 0.6 + cloud2 * 0.4;\r\n\r\n    // Make clouds more defined but still soft\r\n    cloud = smoothstep(0.45, 0.65, cloud);\r\n\r\n    // Clouds more prominent in middle and lower areas\r\n    cloud *= smoothstep(1.0, 0.3, uv.y);\r\n\r\n    return cloud;\r\n}\r\n\r\n// Subtle sun rays from top of screen\r\nfloat sunRays(vec2 uv, float time) {\r\n    // Convert to polar-like coordinates from top center\r\n    vec2 sunPos = vec2(0.5, 1.2); // Sun position (above screen)\r\n    vec2 toSun = uv - sunPos;\r\n\r\n    float angle = atan(toSun.x, toSun.y);\r\n    float dist = length(toSun);\r\n\r\n    // Create ray pattern\r\n    float rays = sin(angle * 8.0 + time * 0.1) * 0.5 + 0.5;\r\n    rays = pow(rays, 3.0);\r\n\r\n    // Rays stronger near top, fade with distance\r\n    float rayFade = smoothstep(1.2, 0.4, dist) * smoothstep(0.0, 0.5, uv.y);\r\n    rays *= rayFade;\r\n\r\n    // Add noise variation to rays\r\n    rays *= 0.5 + 0.5 * fbm(vec2(angle * 2.0, dist * 3.0 + time * 0.05), 3);\r\n\r\n    return rays * 0.08; // Very subtle\r\n}\r\n\r\n// Atmospheric haze/glow effect\r\nfloat atmosphericGlow(vec2 uv) {\r\n    // Warmer glow near horizon (bottom)\r\n    float horizon = 1.0 - uv.y;\r\n    float glow = pow(horizon, 2.5) * 0.3;\r\n\r\n    // Add slight variation\r\n    glow *= 0.8 + 0.2 * valueNoise(uv * 5.0);\r\n\r\n    return glow;\r\n}\r\n\r\n// Subtle depth variation in sky\r\nfloat skyDepth(vec2 uv, float time) {\r\n    // Very subtle noise for sky texture\r\n    float depth = fbm(uv * 6.0 + vec2(time * 0.005, time * 0.003), 4);\r\n    return depth * 0.03; // Very subtle\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    vec2 uv_scaled = uv * 2.0 - 1.0;\r\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\r\n\r\n    // Day sky color palette\r\n    vec3 sky_top = vec3(0.53, 0.81, 0.92);        // #87CEEB - Sky blue\r\n    vec3 sky_middle = vec3(0.68, 0.87, 0.95);     // #ADE0F3 - Lighter blue\r\n    vec3 sky_bottom = vec3(0.99, 0.93, 0.82);     // #FDE9D1 - Warm horizon\r\n    vec3 golden_glow = vec3(0.99, 0.72, 0.39);    // #FDB863 - Golden\r\n    vec3 cloud_color = vec3(0.98, 0.98, 1.00);    // #FAFAFF - White clouds\r\n    vec3 cloud_shadow = vec3(0.85, 0.88, 0.92);   // #D9E0EB - Cloud shadows\r\n\r\n    // Base sky gradient (top to bottom)\r\n    vec3 base_sky = mix(sky_top, sky_middle, uv.y);\r\n    base_sky = mix(base_sky, sky_bottom, pow(uv.y, 1.5));\r\n\r\n    // Add golden glow near horizon\r\n    float horizon_glow = atmosphericGlow(uv);\r\n    base_sky = mix(base_sky, golden_glow, horizon_glow);\r\n\r\n    // Add subtle depth texture\r\n    float depth = skyDepth(uv, u_time);\r\n    base_sky += depth;\r\n\r\n    // Generate clouds\r\n    float cloud = clouds(uv, u_time);\r\n\r\n    // Cloud coloring (mix white with slight shadow)\r\n    vec3 cloud_mix = mix(cloud_color, cloud_shadow, 0.3);\r\n\r\n    // Apply clouds to sky\r\n    vec3 color = mix(base_sky, cloud_mix, cloud * 0.4);\r\n\r\n    // Add subtle sun rays\r\n    float rays = sunRays(uv, u_time);\r\n    color += golden_glow * rays;\r\n\r\n    // Very subtle overall brightness variation\r\n    float ambient = fbm(uv * 4.0 + u_time * 0.01, 3) * 0.02;\r\n    color += ambient;\r\n\r\n    // Slight vignette for depth (very subtle)\r\n    float vignette = smoothstep(1.8, 0.3, length(uv_scaled));\r\n    color *= 0.95 + 0.05 * vignette;\r\n\r\n    // Apply intensity control\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}\r\n";

window.SHADER_SOURCES["earth-shader.glsl"] = "precision highp float;\r\n\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// ENHANCED EARTH SHADER - Living Meadow Theme\r\n// Features: Organic patterns, Voronoi cells, flowing particles, plant growth\r\n// NEW: Swaying grass, dandelion seeds, edge flowers - living meadow feel\r\n// ============================================================================\r\n\r\n// High-quality hash functions\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\n// Quintic interpolation\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\n// Smooth value noise\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = fract(p);\r\n    f = quintic(f);\r\n\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\n// FBM for organic textures\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    float frequency = 1.0;\r\n\r\n    for(int i = 0; i < 8; i++) {\r\n        if(i >= octaves) break;\r\n        value += amplitude * valueNoise(p * frequency);\r\n        frequency *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Voronoi pattern for organic earth texture\r\nvec2 voronoi(vec2 p) {\r\n    vec2 n = floor(p);\r\n    vec2 f = fract(p);\r\n\r\n    float minDist = 8.0;\r\n    vec2 minPoint;\r\n\r\n    for(int j = -1; j <= 1; j++) {\r\n        for(int i = -1; i <= 1; i++) {\r\n            vec2 neighbor = vec2(float(i), float(j));\r\n            vec2 point = hash22(n + neighbor);\r\n\r\n            // Animate points slowly for organic movement\r\n            point += 0.3 * vec2(\r\n                sin(u_time * 0.1 + hash12(n + neighbor) * 6.28),\r\n                cos(u_time * 0.12 + hash12(n + neighbor + 1.0) * 6.28)\r\n            );\r\n\r\n            vec2 diff = neighbor + point - f;\r\n            float dist = length(diff);\r\n\r\n            if(dist < minDist) {\r\n                minDist = dist;\r\n                minPoint = point;\r\n            }\r\n        }\r\n    }\r\n\r\n    return vec2(minDist, hash12(minPoint));\r\n}\r\n\r\n// Growth/plant-like pattern\r\nfloat growthPattern(vec2 uv, float time) {\r\n    vec2 p = uv * 8.0;\r\n\r\n    // Flowing growth direction\r\n    vec2 flow = vec2(\r\n        fbm(p * 0.5 + vec2(time * 0.05, 0.0), 3),\r\n        fbm(p * 0.5 + vec2(0.0, time * 0.06), 3)\r\n    );\r\n\r\n    // Branch-like structure\r\n    float growth = fbm(p + flow * 2.0, 4);\r\n\r\n    // Add veiny structure\r\n    vec2 voro = voronoi(p * 2.0);\r\n    growth += voro.x * 0.3;\r\n\r\n    return growth;\r\n}\r\n\r\n// Flowing particles with natural movement\r\nfloat particles(vec2 uv_scaled, float time) {\r\n    float particle = 0.0;\r\n\r\n    for(int i = 0; i < 18; i++) {\r\n        float fi = float(i);\r\n        float seed = hash12(vec2(fi, 0.0));\r\n\r\n        // Varied lifetime for each particle\r\n        float lifetime = 5.0 + seed * 3.0;\r\n        float t = mod(time * 0.08 + seed * lifetime, lifetime) / lifetime;\r\n\r\n        // Starting position\r\n        vec2 start_pos = vec2(\r\n            hash12(vec2(fi, 1.0)) * 2.0 - 1.0,\r\n            hash12(vec2(fi, 2.0)) * 2.0 - 1.0\r\n        );\r\n\r\n        // Organic floating motion (circular/spiral paths)\r\n        float angle = t * 6.28 + fi;\r\n        float radius = 0.3 + sin(time * 0.2 + fi) * 0.2;\r\n\r\n        vec2 particle_pos = start_pos + vec2(\r\n            cos(angle) * radius * t,\r\n            sin(angle) * radius * t\r\n        );\r\n\r\n        // Add drift\r\n        particle_pos += vec2(\r\n            fbm(vec2(fi, time * 0.1), 2) * 0.3,\r\n            fbm(vec2(fi + 10.0, time * 0.12), 2) * 0.3\r\n        );\r\n\r\n        float dist = length(uv_scaled - particle_pos);\r\n        float size = 0.01 + hash12(vec2(fi, 3.0)) * 0.02;\r\n\r\n        // Particle with soft edges\r\n        float core = smoothstep(size, size * 0.4, dist);\r\n        float glow = smoothstep(size * 3.0, 0.0, dist) * 0.4;\r\n\r\n        // Pulsing animation\r\n        float pulse = 0.7 + 0.3 * sin(time * 2.0 + fi * 2.0);\r\n\r\n        // Smooth fade in/out\r\n        float fade = sin(t * 3.14159);\r\n\r\n        particle += (core + glow) * pulse * fade;\r\n    }\r\n\r\n    return particle;\r\n}\r\n\r\n// NEW: Swaying grass blades on bottom edge (living meadow)\r\nfloat grassBlades(vec2 uv, float time) {\r\n    // Only render grass at bottom 5-10% of screen\r\n    if(uv.y > 0.1) return 0.0;\r\n\r\n    float grass = 0.0;\r\n    vec2 p = vec2(uv.x * 80.0, uv.y * 20.0);\r\n\r\n    // Multiple grass blades\r\n    for(int i = 0; i < 30; i++) {\r\n        float fi = float(i);\r\n        float x = fi * 2.7 + hash12(vec2(fi, 0.0)) * 2.0;\r\n\r\n        // Blade position\r\n        float blade_x = p.x - x;\r\n\r\n        // Sway motion (wind effect)\r\n        float sway = sin(time * 1.5 + fi * 0.5) * 0.3;\r\n        float height = uv.y * 20.0;\r\n\r\n        // Blade shape (tapering toward top)\r\n        float blade_width = 0.08 * (1.0 - height * 8.0);\r\n        float blade = smoothstep(blade_width, 0.0, abs(blade_x - sway * height));\r\n\r\n        // Fade at top of grass\r\n        blade *= smoothstep(0.12, 0.0, uv.y);\r\n\r\n        grass += blade;\r\n    }\r\n\r\n    return grass * 0.5;\r\n}\r\n\r\n// NEW: Dandelion seeds floating upward\r\nfloat dandelionSeeds(vec2 uv_scaled, vec2 uv, float time) {\r\n    float seeds = 0.0;\r\n\r\n    for(int i = 0; i < 8; i++) {\r\n        float fi = float(i);\r\n        float seed = hash12(vec2(fi, 10.0));\r\n\r\n        // Seed lifetime (floating up from meadow)\r\n        float lifetime = 6.0 + seed * 3.0;\r\n        float t = mod(time * 0.06 + seed * lifetime, lifetime) / lifetime;\r\n\r\n        // Start from bottom\r\n        vec2 start_pos = vec2(\r\n            hash12(vec2(fi, 11.0)) * 2.0 - 1.0,\r\n            -0.8\r\n        );\r\n\r\n        // Float upward with gentle drift\r\n        float drift = sin(time * 0.8 + fi * 2.0) * 0.3;\r\n        vec2 seed_pos = start_pos + vec2(drift, t * 2.5);\r\n\r\n        // Add wind turbulence\r\n        seed_pos.x += fbm(vec2(fi, time * 0.15), 2) * 0.2;\r\n\r\n        float dist = length(uv_scaled - seed_pos);\r\n        float size = 0.012;\r\n\r\n        // Dandelion seed shape (central seed + wispy parachute)\r\n        float core = smoothstep(size * 0.3, 0.0, dist);\r\n\r\n        // Wispy parachute structure (star-like rays)\r\n        float parachute = 0.0;\r\n        for(int j = 0; j < 6; j++) {\r\n            float angle = float(j) * 6.28 / 6.0 + time * 0.5 + fi;\r\n            vec2 ray_dir = vec2(cos(angle), sin(angle));\r\n            vec2 to_seed = uv_scaled - seed_pos;\r\n            float ray_dist = abs(dot(to_seed, vec2(-ray_dir.y, ray_dir.x)));\r\n            float along = dot(to_seed, ray_dir);\r\n\r\n            if(along > 0.0 && along < size * 4.0) {\r\n                parachute += smoothstep(size * 0.15, 0.0, ray_dist) * (1.0 - along / (size * 4.0));\r\n            }\r\n        }\r\n\r\n        // Fade in/out during lifetime\r\n        float fade = sin(t * 3.14159);\r\n\r\n        seeds += (core + parachute * 0.3) * fade * 0.6;\r\n    }\r\n\r\n    return seeds;\r\n}\r\n\r\n// NEW: Small flowers/plants growing at borders\r\nfloat edgeFlowers(vec2 uv_scaled, vec2 uv, float time) {\r\n    float flowers = 0.0;\r\n\r\n    // Only on bottom and side edges\r\n    float edge_dist = min(min(uv.y, 1.0 - uv.y), min(uv.x, 1.0 - uv.x));\r\n    if(edge_dist > 0.08) return 0.0;\r\n\r\n    for(int i = 0; i < 12; i++) {\r\n        float fi = float(i);\r\n        float seed = hash12(vec2(fi, 20.0));\r\n\r\n        // Flower position (at edges)\r\n        vec2 flower_pos;\r\n        if(seed < 0.4) {\r\n            // Bottom edge\r\n            flower_pos = vec2(\r\n                hash12(vec2(fi, 21.0)) * 2.0 - 1.0,\r\n                -0.75 - hash12(vec2(fi, 22.0)) * 0.15\r\n            );\r\n        } else if(seed < 0.7) {\r\n            // Left edge\r\n            flower_pos = vec2(\r\n                -0.85 - hash12(vec2(fi, 21.0)) * 0.15,\r\n                hash12(vec2(fi, 22.0)) * 2.0 - 1.0\r\n            );\r\n        } else {\r\n            // Right edge\r\n            flower_pos = vec2(\r\n                0.85 + hash12(vec2(fi, 21.0)) * 0.15,\r\n                hash12(vec2(fi, 22.0)) * 2.0 - 1.0\r\n            );\r\n        }\r\n\r\n        // Gentle swaying in wind\r\n        flower_pos.x += sin(time * 0.5 + fi) * 0.02;\r\n\r\n        float dist = length(uv_scaled - flower_pos);\r\n        float size = 0.015 + hash12(vec2(fi, 23.0)) * 0.01;\r\n\r\n        // Simple flower shape (5 petals)\r\n        float flower = 0.0;\r\n        for(int j = 0; j < 5; j++) {\r\n            float angle = float(j) * 6.28 / 5.0 + time * 0.1;\r\n            vec2 petal_offset = vec2(cos(angle), sin(angle)) * size * 0.8;\r\n            float petal_dist = length(uv_scaled - flower_pos - petal_offset);\r\n            flower += smoothstep(size * 0.6, size * 0.3, petal_dist);\r\n        }\r\n\r\n        // Flower center\r\n        flower += smoothstep(size * 0.4, size * 0.2, dist);\r\n\r\n        flowers += flower * 0.3;\r\n    }\r\n\r\n    return flowers;\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    vec2 uv_scaled = uv * 2.0 - 1.0;\r\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\r\n\r\n    // Organic earth pattern using Voronoi\r\n    vec2 voro = voronoi(uv * 6.0);\r\n    float pattern = smoothstep(0.0, 0.6, voro.x);\r\n\r\n    // Growth pattern\r\n    float growth = growthPattern(uv, u_time);\r\n    growth = smoothstep(0.3, 0.7, growth);\r\n\r\n    // Multi-octave noise for rich texture\r\n    float texture1 = fbm(uv * 10.0 + u_time * 0.03, 5);\r\n    float texture2 = fbm(uv * 15.0 - u_time * 0.02, 4);\r\n\r\n    // Flowing particles\r\n    float particle_val = particles(uv_scaled, u_time);\r\n\r\n    // NEW: Living meadow features\r\n    float grass = grassBlades(uv, u_time);\r\n    float seeds = dandelionSeeds(uv_scaled, uv, u_time);\r\n    float flowers = edgeFlowers(uv_scaled, uv, u_time);\r\n\r\n    // Earthy color palette\r\n    vec3 dark_soil = vec3(0.06, 0.04, 0.02);       // #0f0a05\r\n    vec3 medium_earth = vec3(0.1, 0.08, 0.06);     // #1a1410\r\n    vec3 dark_green = vec3(0.18, 0.29, 0.17);      // #2d4a2b\r\n    vec3 light_green = vec3(0.23, 0.37, 0.21);     // #3a5f35\r\n    vec3 grass_color = vec3(0.25, 0.42, 0.23);     // #409e3a - Bright grass\r\n    vec3 flower_color = vec3(0.45, 0.35, 0.15);    // #725926 - Earthy flowers\r\n    vec3 seed_color = vec3(0.85, 0.85, 0.82);      // #D9D9D1 - Light seeds\r\n\r\n    // Base color from Voronoi pattern\r\n    vec3 base_color = mix(dark_soil, medium_earth, pattern);\r\n\r\n    // Add growth pattern (greenish tint)\r\n    base_color = mix(base_color, dark_green, growth * 0.4);\r\n\r\n    // Add texture layers\r\n    base_color += (texture1 - 0.5) * 0.05;\r\n    base_color += (texture2 - 0.5) * 0.03;\r\n\r\n    // Add particles with earthy glow\r\n    vec3 particle_color = mix(medium_earth, light_green, particle_val * 0.5);\r\n    base_color += particle_color * particle_val * 0.35;\r\n\r\n    // NEW: Add grass (bright green at bottom)\r\n    base_color = mix(base_color, grass_color, grass * 0.6);\r\n\r\n    // NEW: Add dandelion seeds (light, floating)\r\n    base_color = mix(base_color, seed_color, seeds * 0.4);\r\n\r\n    // NEW: Add edge flowers (warm earthy blooms)\r\n    base_color = mix(base_color, flower_color, flowers * 0.5);\r\n\r\n    // Subtle vignette for depth\r\n    float vignette = smoothstep(1.5, 0.5, length(uv_scaled));\r\n    base_color *= 0.7 + 0.3 * vignette;\r\n\r\n    // Apply intensity control\r\n    vec3 color = base_color * u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}\r\n";

window.SHADER_SOURCES["fire-shader.glsl"] = "precision highp float;\n\nuniform vec2 u_resolution;\nuniform float u_time;\nuniform float u_intensity;\n\n// ============================================================================\n// PRODUCTION FIRE SHADER - ShaderToy Inspired\n// Features: Edge flames with domain warping, rising embers, heat shimmer\n// ============================================================================\n\n// High-quality hash function\nfloat hash12(vec2 p) {\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\n    p3 += dot(p3, p3.yzx + 33.33);\n    return fract((p3.x + p3.y) * p3.z);\n}\n\nvec2 hash22(vec2 p) {\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\n    p3 += dot(p3, p3.yzx + 33.33);\n    return fract((p3.xx + p3.yz) * p3.zy);\n}\n\n// Quintic interpolation\nvec2 quintic(vec2 t) {\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\n}\n\n// Smooth value noise\nfloat valueNoise(vec2 p) {\n    vec2 i = floor(p);\n    vec2 f = fract(p);\n    f = quintic(f);\n\n    float a = hash12(i);\n    float b = hash12(i + vec2(1.0, 0.0));\n    float c = hash12(i + vec2(0.0, 1.0));\n    float d = hash12(i + vec2(1.0, 1.0));\n\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\n}\n\n// FBM with variable octaves\nfloat fbm(vec2 p, int octaves) {\n    float value = 0.0;\n    float amplitude = 0.5;\n    float frequency = 1.0;\n\n    for(int i = 0; i < 8; i++) {\n        if(i >= octaves) break;\n        value += amplitude * valueNoise(p * frequency);\n        frequency *= 2.0;\n        amplitude *= 0.5;\n    }\n    return value;\n}\n\n// Domain-warped fire effect\nfloat firePattern(vec2 uv, float time) {\n    // Rising flame motion\n    vec2 p = uv;\n    p.y -= time * 0.4;\n\n    // Multi-layer domain warping for realistic flame turbulence\n    vec2 warp1 = vec2(\n        fbm(p * 2.0 + vec2(time * 0.15, 0.0), 4),\n        fbm(p * 2.0 + vec2(0.0, time * 0.2), 4)\n    );\n\n    vec2 warp2 = vec2(\n        fbm(p * 3.0 + warp1 * 1.5 + vec2(time * 0.1, 0.0), 3),\n        fbm(p * 3.0 + warp1 * 1.5 + vec2(0.0, time * 0.12), 3)\n    );\n\n    // Final fire pattern\n    float fire = fbm(p + warp2 * 2.5, 5);\n\n    // Sharpen flame edges\n    fire = pow(fire, 1.8);\n\n    // Add flickering\n    fire *= 0.85 + 0.15 * sin(time * 8.0 + uv.x * 10.0);\n\n    return fire;\n}\n\n// Rising embers with natural drift\nfloat embers(vec2 uv_scaled, float time) {\n    float ember = 0.0;\n\n    for(int i = 0; i < 12; i++) {\n        float fi = float(i);\n        float seed = hash12(vec2(fi, 0.0));\n\n        // Stagger ember timing\n        float lifetime = 4.0 + seed * 2.0;\n        float t = mod(time * 0.1 + seed * lifetime, lifetime) / lifetime;\n\n        // Starting position\n        vec2 start_pos = vec2(\n            hash12(vec2(fi, 1.0)) * 2.0 - 1.0,\n            -0.7\n        );\n\n        // Natural drift using turbulence\n        float drift_x = sin(time * 0.3 + fi) * 0.3 + fbm(vec2(fi, time * 0.1), 2) * 0.2;\n        float drift_y = t * 2.5;\n\n        vec2 ember_pos = start_pos + vec2(drift_x, drift_y);\n\n        float dist = length(uv_scaled - ember_pos);\n        float size = 0.008 + hash12(vec2(fi, 2.0)) * 0.012;\n\n        // Ember core\n        float core = smoothstep(size, size * 0.3, dist);\n\n        // Ember glow (larger, softer)\n        float glow = smoothstep(size * 4.0, 0.0, dist) * 0.5;\n\n        // Flickering animation\n        float flicker = 0.6 + 0.4 * sin(time * 6.0 + fi * 3.0) * sin(time * 4.0 + fi * 2.0);\n\n        // Fade as ember rises\n        float fade = (1.0 - pow(t, 0.8)) * smoothstep(0.0, 0.1, t);\n\n        ember += (core + glow) * flicker * fade;\n    }\n\n    return ember;\n}\n\n// Heat shimmer distortion effect\nvec2 heatDistortion(vec2 uv, float time) {\n    vec2 distortion = vec2(\n        fbm(uv * 6.0 + vec2(time * 0.2, 0.0), 3),\n        fbm(uv * 6.0 + vec2(0.0, time * 0.25), 3)\n    );\n\n    return (distortion - 0.5) * 0.015;\n}\n\nvoid main() {\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\n    vec2 uv_scaled = uv * 2.0 - 1.0;\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\n\n    // Apply subtle heat distortion\n    uv += heatDistortion(uv, u_time);\n\n    // Edge detection - flames only at edges (5-10% from borders)\n    float edge_dist = min(min(uv.x, 1.0 - uv.x), min(uv.y, 1.0 - uv.y));\n    float edge_mask = smoothstep(0.1, 0.05, edge_dist);\n\n    // Fire at edges with domain warping\n    float fire_val = 0.0;\n    if(edge_mask > 0.01) {\n        vec2 fire_uv = uv * 4.0;\n        fire_val = firePattern(fire_uv, u_time) * edge_mask;\n    }\n\n    // Rising embers throughout\n    float ember_val = embers(uv_scaled, u_time);\n\n    // Rich ember color palette\n    vec3 base_color = vec3(0.04, 0.07, 0.05);          // #0a0500 (very dark)\n    vec3 dark_ember = vec3(0.18, 0.07, 0.0);           // #2d1200 (dark brown)\n    vec3 hot_ember = vec3(0.55, 0.15, 0.0);            // #8b2500 (red-orange)\n    vec3 bright_ember = vec3(1.0, 0.42, 0.1);          // #ff6b1a (bright orange)\n\n    // Ambient glow\n    float ambient_glow = fbm(uv * 3.0 + u_time * 0.05, 3) * 0.02;\n\n    // Build fire color with temperature gradient\n    vec3 fire_color = mix(dark_ember, hot_ember, fire_val);\n    fire_color = mix(fire_color, bright_ember, pow(fire_val, 2.0));\n\n    // Combine effects\n    vec3 color = base_color;\n\n    // Add fire at edges\n    color += fire_color * fire_val * 0.25;\n\n    // Add embers with color gradient\n    vec3 ember_color = mix(hot_ember, bright_ember, pow(ember_val, 1.5));\n    color += ember_color * ember_val * 0.4;\n\n    // Add subtle ambient glow\n    color += dark_ember * ambient_glow;\n\n    // Apply intensity control\n    color *= u_intensity;\n\n    gl_FragColor = vec4(color, 1.0);\n}\n";

window.SHADER_SOURCES["light-shader.glsl"] = "precision highp float;\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// GOLDEN LIGHT SHADER - Warm volumetric light, dust motes, caustics\r\n// Features: Light beams, floating dust, caustic patterns, warm vignette\r\n// ============================================================================\r\n\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = fract(p);\r\n    f = quintic(f);\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    for (int i = 0; i < 8; i++) {\r\n        if (i >= octaves) break;\r\n        value += amplitude * valueNoise(p);\r\n        p *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Soft volumetric light beam from upper-right, gently swaying\r\nfloat lightBeam(vec2 uv, float beamAngle, float beamWidth, float sway, float t) {\r\n    // Beam origin at upper-right\r\n    vec2 origin = vec2(0.75 + sway * 0.03, 1.02);\r\n    vec2 dir = vec2(cos(beamAngle), sin(beamAngle));\r\n    vec2 toUV = uv - origin;\r\n    float along = dot(toUV, dir);\r\n    float perp = length(toUV - dir * along);\r\n    float width = beamWidth + along * 0.08;\r\n    float beam = smoothstep(width, width * 0.3, perp);\r\n    beam *= smoothstep(0.0, 0.15, along);\r\n    beam *= smoothstep(1.2, 0.3, along);\r\n    // Soft noise modulation along beam\r\n    float noiseAlong = fbm(vec2(along * 3.0 + t * 0.05, perp * 8.0), 3);\r\n    beam *= 0.6 + 0.4 * noiseAlong;\r\n    return max(0.0, beam);\r\n}\r\n\r\n// Voronoi for caustic patterns\r\nfloat voronoi(vec2 p, float t) {\r\n    vec2 n = floor(p);\r\n    vec2 f = fract(p);\r\n    float d = 1.0;\r\n    for (int j = -1; j <= 1; j++) {\r\n        for (int i = -1; i <= 1; i++) {\r\n            vec2 g = vec2(float(i), float(j));\r\n            vec2 o = hash22(n + g);\r\n            o = 0.5 + 0.5 * sin(t * 0.15 + 6.2831 * o);\r\n            float dist = length(g + o - f);\r\n            if (dist < d) d = dist;\r\n        }\r\n    }\r\n    return d;\r\n}\r\n\r\n// Dust mote: tiny soft circular particle\r\nfloat dustMote(vec2 uv, vec2 pos, float sz) {\r\n    float d = length(uv - pos);\r\n    return smoothstep(sz, sz * 0.1, d);\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    float aspect = u_resolution.x / u_resolution.y;\r\n    vec2 c = uv * 2.0 - 1.0;\r\n    c.x *= aspect;\r\n\r\n    // ── Warm color palette ──────────────────────────────────────────────────\r\n    vec3 warmCream   = vec3(0.96, 0.92, 0.82);\r\n    vec3 sunAmber    = vec3(0.88, 0.68, 0.22);\r\n    vec3 deepGold    = vec3(0.72, 0.52, 0.12);\r\n    vec3 lightStraw  = vec3(0.98, 0.96, 0.88);\r\n    vec3 roseGold    = vec3(0.92, 0.74, 0.48);\r\n\r\n    // ── Background warm gradient: warmer top, slightly cooler bottom ────────\r\n    float warmGrad = smoothstep(0.0, 1.0, uv.y);\r\n    vec3 bgColor = mix(warmCream * 0.09, warmCream * 0.06, warmGrad);\r\n    bgColor = mix(bgColor, sunAmber * 0.04, (1.0 - uv.y) * 0.5);\r\n\r\n    // ── Slow background FBM for atmospheric depth ────────────────────────\r\n    float bgNoise = fbm(uv * 2.5 + u_time * 0.015, 4);\r\n    float bgNoise2 = fbm(uv * 4.0 - u_time * 0.01, 3);\r\n    bgColor += warmCream * bgNoise * 0.018;\r\n    bgColor += sunAmber * bgNoise2 * 0.010;\r\n\r\n    // ── Light beams from upper-right, gently swaying ────────────────────────\r\n    float sway1 = sin(u_time * 0.18) * 0.5;\r\n    float sway2 = sin(u_time * 0.23 + 1.2) * 0.5;\r\n    float sway3 = sin(u_time * 0.13 + 2.8) * 0.5;\r\n\r\n    float beam1 = lightBeam(uv, -2.05 + sway1 * 0.02, 0.035, sway1, u_time);\r\n    float beam2 = lightBeam(uv, -2.15 + sway2 * 0.02, 0.025, sway2, u_time);\r\n    float beam3 = lightBeam(uv, -1.95 + sway3 * 0.02, 0.045, sway3, u_time);\r\n\r\n    vec3 beamColor = sunAmber * 0.07;\r\n    vec3 beams = beamColor * (beam1 + beam2 * 0.7 + beam3 * 0.5);\r\n\r\n    // ── Caustic patterns: sunlight refraction ────────────────────────────\r\n    float v1 = voronoi(uv * 5.5 + vec2(u_time * 0.04, u_time * 0.02), u_time);\r\n    float v2 = voronoi(uv * 8.0 - vec2(u_time * 0.03, u_time * 0.025), u_time);\r\n    float v3 = voronoi(uv * 11.0 + vec2(u_time * 0.02, -u_time * 0.03), u_time);\r\n    float caustic = pow(1.0 - (v1 * 0.5 + v2 * 0.35 + v3 * 0.15), 3.5);\r\n    caustic = smoothstep(0.2, 0.9, caustic) * 0.06;\r\n    // Caustics stronger where beams land\r\n    caustic *= 0.5 + 0.5 * (beam1 + beam2 + beam3);\r\n    vec3 causticColor = mix(sunAmber, lightStraw, 0.5) * caustic;\r\n\r\n    // ── Shimmer layers ──────────────────────────────────────────────────\r\n    float shimmer1 = fbm(uv * 7.0 + u_time * 0.04, 4);\r\n    float shimmer2 = fbm(uv * 13.0 - u_time * 0.03, 3);\r\n    float shimmerCombined = shimmer1 * shimmer2;\r\n    vec3 shimmerColor = sunAmber * pow(shimmerCombined, 2.5) * 0.08;\r\n\r\n    // ── Midground warm glow from upper-right ─────────────────────────────\r\n    vec2 glowOrigin = vec2(0.72, 1.1);\r\n    float glowDist = length(uv - glowOrigin);\r\n    float midGlow = exp(-glowDist * glowDist * 1.8) * 0.12;\r\n    midGlow *= 0.9 + 0.1 * sin(u_time * 0.4);\r\n    vec3 midGlowColor = mix(lightStraw, sunAmber, 0.4) * midGlow;\r\n\r\n    // ── Foreground soft shimmer band ─────────────────────────────────────\r\n    float fgShimmer = fbm(vec2(uv.x * 5.0 + u_time * 0.06, uv.y * 3.0), 3);\r\n    fgShimmer = pow(fgShimmer, 3.0) * 0.04;\r\n    vec3 fgColor = roseGold * fgShimmer;\r\n\r\n    // ── Floating dust motes ───────────────────────────────────────────────\r\n    vec3 dustColor = vec3(0.0);\r\n    for (int i = 0; i < 30; i++) {\r\n        float fi = float(i);\r\n        vec2 seed = vec2(fi * 0.137, fi * 0.271);\r\n        // Drift upward slowly, with gentle horizontal oscillation\r\n        float speed = 0.04 + hash12(seed) * 0.04;\r\n        float phase = hash12(seed + 7.3) * 6.28;\r\n        float lifetime = hash12(seed + 13.7) * 6.0;\r\n        float t = mod(u_time * speed + lifetime, 1.0);\r\n        vec2 basePos = vec2(hash12(seed + 1.0), 1.0 - t);\r\n        basePos.x += sin(u_time * 0.2 + phase) * 0.04;\r\n        basePos.x = fract(basePos.x);\r\n        float sz = 0.003 + hash12(seed + 5.0) * 0.006;\r\n        float fade = smoothstep(0.0, 0.1, t) * smoothstep(1.0, 0.85, t);\r\n        float mote = dustMote(uv, basePos, sz) * fade;\r\n        // Warm amber tones, very soft\r\n        vec3 moteColor = mix(sunAmber, lightStraw, hash12(seed + 2.0));\r\n        dustColor += moteColor * mote * 0.04;\r\n    }\r\n\r\n    // ── Warm amber vignette at edges ─────────────────────────────────────\r\n    float vignette = 1.0 - smoothstep(0.5, 1.2, length(c * vec2(0.8, 1.0)));\r\n    vec3 vignetteColor = deepGold * (1.0 - vignette) * 0.05;\r\n\r\n    // ── Temperature shift: warm at top-right, slightly cooler lower-left ─\r\n    float tempShift = uv.x * 0.4 + uv.y * 0.3;\r\n    vec3 tempColor = mix(roseGold * 0.015, sunAmber * 0.01, tempShift);\r\n\r\n    // ── Slow pulse ───────────────────────────────────────────────────────\r\n    float pulse = 0.97 + 0.03 * sin(u_time * 0.35);\r\n\r\n    // ── Compose ──────────────────────────────────────────────────────────\r\n    vec3 color = bgColor;\r\n    color += beams;\r\n    color += causticColor;\r\n    color += shimmerColor;\r\n    color += midGlowColor;\r\n    color += fgColor;\r\n    color += dustColor;\r\n    color += vignetteColor;\r\n    color += tempColor;\r\n    color *= pulse;\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}";

window.SHADER_SOURCES["night-shader.glsl"] = "precision highp float;\n\nuniform vec2 u_resolution;\nuniform float u_time;\nuniform float u_intensity;\n\n// ============================================================================\n// PRODUCTION NIGHT SKY SHADER - ShaderToy Inspired\n// Features: Realistic stars, aurora borealis, nebula, shooting stars\n// ============================================================================\n\n// High-quality hash functions\nfloat hash12(vec2 p) {\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\n    p3 += dot(p3, p3.yzx + 33.33);\n    return fract((p3.x + p3.y) * p3.z);\n}\n\nfloat hash13(vec3 p3) {\n    p3 = fract(p3 * 0.1031);\n    p3 += dot(p3, p3.zxy + 31.32);\n    return fract((p3.x + p3.y) * p3.z);\n}\n\nvec2 hash22(vec2 p) {\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\n    p3 += dot(p3, p3.yzx + 33.33);\n    return fract((p3.xx + p3.yz) * p3.zy);\n}\n\n// Quintic interpolation\nvec2 quintic(vec2 t) {\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\n}\n\n// Smooth value noise\nfloat valueNoise(vec2 p) {\n    vec2 i = floor(p);\n    vec2 f = fract(p);\n    f = quintic(f);\n\n    float a = hash12(i);\n    float b = hash12(i + vec2(1.0, 0.0));\n    float c = hash12(i + vec2(0.0, 1.0));\n    float d = hash12(i + vec2(1.0, 1.0));\n\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\n}\n\n// FBM for organic patterns\nfloat fbm(vec2 p, int octaves) {\n    float value = 0.0;\n    float amplitude = 0.5;\n    float frequency = 1.0;\n\n    for(int i = 0; i < 8; i++) {\n        if(i >= octaves) break;\n        value += amplitude * valueNoise(p * frequency);\n        frequency *= 2.0;\n        amplitude *= 0.5;\n    }\n    return value;\n}\n\n// Realistic star field with varied sizes\nfloat stars(vec2 uv, float layer, float time) {\n    // Different grid sizes for star layers\n    vec2 grid = uv * (120.0 + layer * 80.0);\n    vec2 id = floor(grid);\n    vec2 local = fract(grid);\n\n    float star = 0.0;\n    float h = hash12(id + layer * 100.0);\n\n    // Control star density\n    if(h > 0.92) {\n        // Star position within cell (jittered)\n        vec2 star_pos = vec2(0.5) + (hash22(id + layer * 100.0) - 0.5) * 0.9;\n        float dist = length(local - star_pos);\n\n        // Varied star sizes\n        float size_seed = hash12(id + layer * 100.0 + 10.0);\n        float size = 0.001 + size_seed * 0.004;\n\n        // Twinkling at different speeds\n        float twinkle_speed = 2.0 + h * 4.0;\n        float twinkle = 0.4 + 0.6 * sin(time * twinkle_speed + h * 6.28) *\n                             sin(time * twinkle_speed * 0.7 + h * 3.14);\n\n        // Star brightness\n        float brightness = smoothstep(size, 0.0, dist);\n\n        // Add diffraction spikes for brighter stars\n        if(size_seed > 0.7) {\n            float angle = atan(local.y - star_pos.y, local.x - star_pos.x);\n            float spike = pow(abs(sin(angle * 2.0)), 8.0) * smoothstep(size * 15.0, 0.0, dist);\n            brightness += spike * 0.5;\n        }\n\n        star = brightness * twinkle;\n    }\n\n    return star;\n}\n\n// Realistic aurora borealis\nvec3 aurora(vec2 uv, float time) {\n    // Only in upper portion\n    if(uv.y < 0.55) return vec3(0.0);\n\n    vec2 p = vec2(uv.x * 4.0, uv.y * 2.0);\n\n    // Flowing aurora waves\n    float wave1 = fbm(p + vec2(time * 0.08, time * 0.05), 4);\n    float wave2 = fbm(p * 1.3 - vec2(time * 0.06, time * 0.04), 4);\n    float wave3 = fbm(p * 0.8 + vec2(time * 0.1, -time * 0.03), 3);\n\n    // Combine waves\n    float aurora_val = (wave1 + wave2 * 0.7 + wave3 * 0.5) / 2.2;\n\n    // Shape aurora to upper sky\n    aurora_val *= smoothstep(0.55, 0.7, uv.y);\n    aurora_val *= 1.0 - smoothstep(0.85, 0.95, uv.y);\n\n    // Add curtain-like vertical structure\n    aurora_val *= 0.7 + 0.3 * sin(uv.x * 15.0 + wave1 * 3.0);\n\n    aurora_val = pow(aurora_val, 1.5);\n\n    // Aurora colors - green, purple, blue\n    vec3 green = vec3(0.1, 0.5, 0.3);\n    vec3 purple = vec3(0.4, 0.1, 0.5);\n    vec3 blue = vec3(0.1, 0.3, 0.6);\n\n    // Color variation across aurora\n    vec3 aurora_color = mix(green, purple, wave2);\n    aurora_color = mix(aurora_color, blue, wave3 * 0.5);\n\n    return aurora_color * aurora_val * 0.4;\n}\n\n// Subtle flowing nebula\nvec3 nebula(vec2 uv, float time) {\n    vec2 p = uv * 2.0;\n\n    float n1 = fbm(p + vec2(time * 0.02, time * 0.015), 5);\n    float n2 = fbm(p * 1.5 + vec2(-time * 0.018, time * 0.012), 4);\n\n    float nebula_val = (n1 + n2) * 0.5;\n    nebula_val = pow(nebula_val, 2.0);\n\n    // Nebula colors - very subtle purple and blue\n    vec3 purple = vec3(0.08, 0.04, 0.12);\n    vec3 blue = vec3(0.04, 0.06, 0.15);\n\n    return mix(purple, blue, n2) * nebula_val * 0.3;\n}\n\n// Occasional shooting star\nfloat shootingStar(vec2 uv, float time) {\n    // One shooting star every 12-15 seconds\n    float period = 13.0;\n    float t = mod(time, period);\n\n    // Only show for brief moment\n    if(t > 0.8) return 0.0;\n\n    // Smooth appearance\n    float fade = smoothstep(0.0, 0.1, t) * (1.0 - smoothstep(0.4, 0.8, t));\n\n    // Shooting star path (diagonal)\n    float star_seed = floor(time / period);\n    float start_x = hash13(vec3(star_seed, 0.0, 0.0)) * 1.5 - 0.25;\n    float start_y = 0.5 + hash13(vec3(star_seed, 1.0, 0.0)) * 0.4;\n\n    vec2 star_start = vec2(start_x, start_y);\n    vec2 star_velocity = vec2(1.2, -0.6);\n    vec2 star_pos = star_start + star_velocity * t;\n\n    // Distance to shooting star trail\n    vec2 to_star = uv - star_pos;\n    vec2 trail_dir = normalize(star_velocity);\n    float along_trail = dot(to_star, trail_dir);\n    float dist_to_trail = length(to_star - trail_dir * along_trail);\n\n    // Trail extends behind star\n    float trail = 0.0;\n    if(along_trail < 0.0 && along_trail > -0.15) {\n        trail = smoothstep(0.003, 0.0, dist_to_trail) * (1.0 + along_trail / 0.15);\n    }\n\n    // Star head\n    float dist = length(uv - star_pos);\n    float head = smoothstep(0.005, 0.0, dist);\n\n    return (head + trail * 0.6) * fade;\n}\n\nvoid main() {\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\n    vec2 uv_scaled = uv * 2.0 - 1.0;\n    uv_scaled.x *= u_resolution.x / u_resolution.y;\n\n    // Deep night sky gradient\n    vec3 deep_sky = vec3(0.02, 0.04, 0.08);        // #050a15\n    vec3 horizon_sky = vec3(0.04, 0.06, 0.12);     // #0a0e1f\n    vec3 mid_sky = vec3(0.1, 0.12, 0.23);          // #1a1f3a\n\n    // Vertical gradient\n    vec3 sky_color = mix(horizon_sky, deep_sky, smoothstep(0.0, 0.4, uv.y));\n    sky_color = mix(sky_color, mid_sky, smoothstep(0.6, 1.0, uv.y));\n\n    // Multiple star layers for depth and realism\n    float star_val = 0.0;\n    star_val += stars(uv_scaled, 0.0, u_time) * 1.0;          // Foreground stars\n    star_val += stars(uv_scaled, 1.0, u_time * 0.8) * 0.7;    // Mid stars\n    star_val += stars(uv_scaled, 2.0, u_time * 0.6) * 0.5;    // Background stars\n    star_val += stars(uv_scaled, 3.0, u_time * 0.9) * 0.8;    // Additional layer\n\n    // Star colors (slightly warm white)\n    vec3 star_color = vec3(1.0, 0.95, 0.9) * star_val;\n\n    // Aurora borealis\n    vec3 aurora_color = aurora(uv, u_time);\n\n    // Subtle nebula clouds\n    vec3 nebula_color = nebula(uv, u_time);\n\n    // Shooting star\n    float shooting = shootingStar(uv, u_time);\n    vec3 shooting_color = vec3(0.9, 0.95, 1.0) * shooting;\n\n    // Combine all elements\n    vec3 color = sky_color;\n    color += nebula_color;\n    color += aurora_color;\n    color += star_color;\n    color += shooting_color;\n\n    // Apply intensity control\n    color *= u_intensity;\n\n    gl_FragColor = vec4(color, 1.0);\n}\n";

window.SHADER_SOURCES["order-shader.glsl"] = "precision highp float;\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// WHITE MARBLE SHADER - Veined marble with sacred geometry overlay\r\n// Features: Multi-scale veining, golden flecks, light play, Flower of Life\r\n// ============================================================================\r\n\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = quintic(fract(p));\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    for (int i = 0; i < 8; i++) {\r\n        if (i >= octaves) break;\r\n        value += amplitude * valueNoise(p);\r\n        p *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Marble vein function: sharp-edged flowing veins\r\nfloat marbleVein(vec2 p, float scale, float time, float speed) {\r\n    vec2 warp = vec2(\r\n        fbm(p * scale + vec2(time * speed, 0.0), 4),\r\n        fbm(p * scale + vec2(0.0, time * speed * 0.7) + 5.0, 4)\r\n    );\r\n    float v = fbm(p * scale * 0.8 + warp * 1.8, 5);\r\n    // Sharpen into veins using sine trick\r\n    float vein = abs(sin(v * 6.28 * 1.5));\r\n    vein = pow(1.0 - vein, 5.0);\r\n    return vein;\r\n}\r\n\r\n// Flower of Life sacred geometry — concentric circles at hexagonal lattice\r\nfloat flowerOfLife(vec2 uv, float scale) {\r\n    uv = uv * scale;\r\n    // Hexagonal lattice vectors\r\n    vec2 a1 = vec2(1.0, 0.0);\r\n    vec2 a2 = vec2(0.5, 0.8660254);\r\n    // Find nearest hexagonal lattice points (up to ring-1 neighbors)\r\n    float minDist = 1.0;\r\n    for (int i = -2; i <= 2; i++) {\r\n        for (int j = -2; j <= 2; j++) {\r\n            vec2 center = float(i) * a1 + float(j) * a2;\r\n            float d = length(uv - center);\r\n            minDist = min(minDist, d);\r\n        }\r\n    }\r\n    // Circle ring at radius 1.0 from each lattice point\r\n    float ring = abs(minDist - 1.0);\r\n    return smoothstep(0.025, 0.0, ring);\r\n}\r\n\r\n// Metatron's Cube: additional line pattern\r\nfloat metatronLines(vec2 uv, float scale) {\r\n    uv = uv * scale;\r\n    // 6-fold star lines\r\n    float lines = 0.0;\r\n    for (int k = 0; k < 6; k++) {\r\n        float angle = float(k) * 3.14159 / 3.0;\r\n        vec2 dir = vec2(cos(angle), sin(angle));\r\n        float lineDist = abs(dot(uv - dir * 0.5, vec2(-dir.y, dir.x)));\r\n        lines += smoothstep(0.012, 0.0, lineDist) * step(0.0, dot(uv - dir * 0.5, dir)) * step(dot(uv - dir * 1.0, dir), 0.0);\r\n    }\r\n    return clamp(lines, 0.0, 1.0);\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    float aspect = u_resolution.x / u_resolution.y;\r\n    vec2 c = uv * 2.0 - 1.0;\r\n    c.x *= aspect;\r\n\r\n    // ── Marble color palette ──────────────────────────────────────────────\r\n    vec3 pureWhite  = vec3(0.97, 0.97, 0.98);\r\n    vec3 warmWhite  = vec3(0.95, 0.94, 0.92);\r\n    vec3 coolWhite  = vec3(0.93, 0.93, 0.96);\r\n    vec3 veinGrey   = vec3(0.74, 0.74, 0.80);\r\n    vec3 veinBlue   = vec3(0.70, 0.72, 0.82);\r\n    vec3 goldFleck  = vec3(0.82, 0.70, 0.30);\r\n    vec3 sacredGold = vec3(0.78, 0.68, 0.38);\r\n\r\n    // ── Multi-scale marble veining ────────────────────────────────────────\r\n    // Primary veins: large-scale, dominant\r\n    float vein1 = marbleVein(uv, 2.0, u_time, 0.008);\r\n    // Secondary veins: medium-scale, cross-cutting\r\n    float vein2 = marbleVein(uv + vec2(0.3, 0.7), 4.5, u_time, 0.006);\r\n    // Fine veins: hairline detail\r\n    float vein3 = marbleVein(uv + vec2(0.9, 0.2), 9.0, u_time, 0.004);\r\n    // Micro veins: finest texture\r\n    float vein4 = marbleVein(uv + vec2(0.5, 0.5), 18.0, u_time, 0.003);\r\n\r\n    // ── Base marble with warm/cool shift ─────────────────────────────────\r\n    float warmCool = smoothstep(0.0, 1.0, uv.x + uv.y * 0.3);\r\n    vec3 baseMarble = mix(warmWhite, coolWhite, warmCool * 0.5);\r\n\r\n    // ── Apply veins at different weights ─────────────────────────────────\r\n    vec3 veinColor1 = mix(veinGrey, veinBlue, 0.4);\r\n    vec3 veinColor2 = mix(veinGrey, veinBlue, 0.7);\r\n\r\n    vec3 color = baseMarble;\r\n    color = mix(color, veinColor1, vein1 * 0.18);\r\n    color = mix(color, veinColor2, vein2 * 0.12);\r\n    color = mix(color, veinGrey,   vein3 * 0.06);\r\n    color = mix(color, veinBlue,   vein4 * 0.03);\r\n\r\n    // ── Golden flecks: very faint, scattered ─────────────────────────────\r\n    float fleckNoise1 = fbm(uv * 22.0 + u_time * 0.003, 2);\r\n    float fleckNoise2 = fbm(uv * 38.0 - u_time * 0.002, 2);\r\n    float fleck = pow(fleckNoise1 * fleckNoise2, 4.0);\r\n    fleck = smoothstep(0.3, 1.0, fleck) * 0.06;\r\n    color = mix(color, goldFleck, fleck);\r\n\r\n    // ── Light play: soft directional shadow gradient ──────────────────────\r\n    // Light from upper-left, shadow lower-right\r\n    float lightAngle = dot(normalize(c), normalize(vec2(-0.6, 0.8)));\r\n    float lightPlay = lightAngle * 0.5 + 0.5;\r\n    lightPlay = smoothstep(0.2, 0.8, lightPlay);\r\n    color += pureWhite * lightPlay * 0.018;\r\n    color -= pureWhite * (1.0 - lightPlay) * 0.012;\r\n\r\n    // ── Subtle shimmer / movement ─────────────────────────────────────────\r\n    float shimmer = fbm(uv * 15.0 + u_time * 0.02, 3);\r\n    float shimmer2 = fbm(uv * 25.0 - u_time * 0.015, 2);\r\n    float shimmerVal = pow(shimmer * shimmer2, 3.0) * 0.04;\r\n    color += pureWhite * shimmerVal;\r\n\r\n    // ── Sacred geometry: Flower of Life, very faint ──────────────────────\r\n    // Animate scale slightly for breathing effect\r\n    float geoScale = 2.8 + 0.05 * sin(u_time * 0.08);\r\n    float fol = flowerOfLife(uv, geoScale);\r\n    float meta = metatronLines(uv, geoScale * 0.5);\r\n    float geo = max(fol, meta * 0.7);\r\n    // Geo is barely perceptible — sacred geometry as hidden structure\r\n    color = mix(color, sacredGold, geo * 0.022);\r\n\r\n    // ── Barely-perceptible breathing pulse ──────────────────────────────\r\n    float pulse = 0.998 + 0.002 * sin(u_time * 0.25);\r\n\r\n    color *= pulse;\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}";

window.SHADER_SOURCES["storm-shader.glsl"] = "precision highp float;\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// STORM SHADER - Layered clouds, lightning, rain, wind shear, atmospheric depth\r\n// Features: 4 cloud layers, lightning flashes, angled rain, purple storm tones\r\n// ============================================================================\r\n\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = quintic(fract(p));\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    for (int i = 0; i < 8; i++) {\r\n        if (i >= octaves) break;\r\n        value += amplitude * valueNoise(p);\r\n        p *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Wind-sheared cloud layer\r\nfloat cloudLayer(vec2 uv, float scale, float speed, float windShear, float time) {\r\n    // Wind stretches clouds horizontally\r\n    vec2 sheared = uv + vec2(uv.y * windShear, 0.0);\r\n    vec2 warp1 = vec2(\r\n        fbm(sheared * scale + vec2(time * speed, 0.0), 4),\r\n        fbm(sheared * scale + vec2(0.0, time * speed * 0.6) + 3.7, 4)\r\n    );\r\n    vec2 warp2 = vec2(\r\n        fbm(sheared * scale * 1.8 + warp1 * 0.8 + vec2(time * speed * 0.7, 0.0), 3),\r\n        fbm(sheared * scale * 1.8 + warp1 * 0.8 + vec2(0.0, time * speed * 0.5) + 7.1, 3)\r\n    );\r\n    float cloud = fbm(sheared * scale * 0.9 + warp2 * 0.6, 5);\r\n    return cloud;\r\n}\r\n\r\n// Lightning channel with branching\r\nfloat lightningChannel(vec2 uv, float seed, float time) {\r\n    float result = 0.0;\r\n    vec2 p = uv;\r\n    float prevX = hash12(vec2(seed, 0.0)) * 0.6 + 0.2;\r\n    // Descend from top in segments\r\n    for (int seg = 0; seg < 8; seg++) {\r\n        float y1 = 1.0 - float(seg) * 0.12;\r\n        float y2 = y1 - 0.12;\r\n        float segSeed = hash12(vec2(seed + float(seg) * 0.17, time * 0.1));\r\n        float nextX = prevX + (segSeed - 0.5) * 0.14;\r\n        nextX = clamp(nextX, 0.1, 0.9);\r\n        // Interpolate along segment\r\n        float t = clamp((uv.y - y2) / (y1 - y2), 0.0, 1.0);\r\n        float boltX = mix(nextX, prevX, t);\r\n        float dist = abs(uv.x - boltX);\r\n        result += smoothstep(0.006, 0.0, dist) * step(y2, uv.y) * step(uv.y, y1);\r\n        // Branch probability\r\n        if (hash12(vec2(seed * 2.3 + float(seg), 1.0)) > 0.6) {\r\n            float branchX = boltX + (hash12(vec2(seed, float(seg) * 0.5)) - 0.5) * 0.2;\r\n            float brachLen = 0.06 + hash12(vec2(seed + 1.0, float(seg))) * 0.08;\r\n            float branchY = mix(y1, y2, 0.5);\r\n            float bt = clamp((uv.y - (branchY - brachLen)) / brachLen, 0.0, 1.0);\r\n            float bx = mix(branchX, boltX, bt);\r\n            float bdist = abs(uv.x - bx);\r\n            result += smoothstep(0.004, 0.0, bdist) * step(branchY - brachLen, uv.y) * step(uv.y, branchY) * 0.5;\r\n        }\r\n        prevX = nextX;\r\n    }\r\n    return clamp(result, 0.0, 1.0);\r\n}\r\n\r\n// Rain streak in depth layers\r\nfloat rainLayer(vec2 uv, float speed, float angle, float density, float time, float layerIdx) {\r\n    float totalRain = 0.0;\r\n    // Slant UV by wind angle\r\n    vec2 slantedUV = vec2(uv.x + uv.y * tan(angle), uv.y);\r\n    int iDensity = int(density);\r\n    for (int i = 0; i < 20; i++) {\r\n        if (i >= iDensity) break;\r\n        float fi = float(i);\r\n        vec2 seed = vec2(fi * 0.137 + layerIdx, fi * 0.271 + layerIdx * 0.5);\r\n        float xOff = hash12(seed) * 2.0 - 1.0;\r\n        float spd = speed + hash12(seed + 0.5) * speed * 0.3;\r\n        float yPhase = fract(slantedUV.y * 0.5 + time * spd + hash12(seed + 1.0) * 4.0);\r\n        float xPos = fract(slantedUV.x + xOff);\r\n        float streak = smoothstep(0.003, 0.0, abs(xPos - 0.5));\r\n        streak *= smoothstep(0.0, 0.03, yPhase) * smoothstep(0.1 + hash12(seed + 2.0) * 0.08, 0.03, yPhase);\r\n        totalRain += streak;\r\n    }\r\n    return clamp(totalRain, 0.0, 1.0);\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n\r\n    // ── Storm color palette ───────────────────────────────────────────────\r\n    vec3 deepStorm    = vec3(0.04, 0.04, 0.08);\r\n    vec3 midCloud     = vec3(0.10, 0.10, 0.17);\r\n    vec3 lightCloud   = vec3(0.16, 0.16, 0.26);\r\n    vec3 purpleCloud  = vec3(0.12, 0.08, 0.18);\r\n    vec3 blueGrey     = vec3(0.08, 0.10, 0.16);\r\n    vec3 lightningWht = vec3(0.85, 0.90, 1.00);\r\n    vec3 lightningBlu = vec3(0.55, 0.65, 1.00);\r\n    vec3 rainColor    = vec3(0.40, 0.45, 0.62);\r\n\r\n    // ── Layer 1: deep background clouds (slow, large) ─────────────────────\r\n    float layer1 = cloudLayer(uv, 1.5, 0.04, 0.4, u_time);\r\n    // ── Layer 2: main storm clouds (medium speed) ─────────────────────────\r\n    float layer2 = cloudLayer(uv + vec2(0.3, 0.1), 2.8, 0.07, 0.6, u_time);\r\n    // ── Layer 3: fast mid-level clouds (more turbulent) ───────────────────\r\n    float layer3 = cloudLayer(uv + vec2(0.7, 0.5), 5.0, 0.12, 0.8, u_time);\r\n    // ── Layer 4: foreground wisps (fastest, finest detail) ────────────────\r\n    float layer4 = cloudLayer(uv + vec2(0.9, 0.8), 9.0, 0.18, 1.0, u_time);\r\n\r\n    // ── Compose cloud layers ─────────────────────────────────────────────\r\n    vec3 cloudColor = deepStorm;\r\n    cloudColor = mix(cloudColor, purpleCloud, layer1 * 0.6);\r\n    cloudColor = mix(cloudColor, midCloud,    layer2 * 0.55);\r\n    cloudColor = mix(cloudColor, blueGrey,    layer2 * layer3 * 0.3);\r\n    cloudColor = mix(cloudColor, lightCloud,  layer3 * 0.35);\r\n    cloudColor += purpleCloud * layer4 * 0.08;\r\n    cloudColor += blueGrey * layer4 * 0.06;\r\n\r\n    // ── Atmospheric depth haze at bottom ─────────────────────────────────\r\n    float bottomHaze = smoothstep(0.3, 0.0, uv.y) * 0.5;\r\n    vec3 hazeColor = blueGrey * 0.4;\r\n    cloudColor = mix(cloudColor, hazeColor, bottomHaze);\r\n\r\n    // ── Purple/blue storm tinting ────────────────────────────────────────\r\n    float stormTint = fbm(uv * 1.5 + u_time * 0.02, 3);\r\n    cloudColor += purpleCloud * stormTint * 0.04;\r\n\r\n    // ── Lightning system ──────────────────────────────────────────────────\r\n    // Flash timing — discrete flash events\r\n    float flashPeriod = 7.0;\r\n    float flashT = mod(u_time, flashPeriod);\r\n    float flashSeed = floor(u_time / flashPeriod);\r\n\r\n    // Secondary flash (different period)\r\n    float flashPeriod2 = 11.3;\r\n    float flashT2 = mod(u_time + 3.7, flashPeriod2);\r\n    float flashSeed2 = floor((u_time + 3.7) / flashPeriod2);\r\n\r\n    // Flash brightness envelope: sharp rise, exponential decay\r\n    float flashActive = step(0.98, hash12(vec2(flashSeed, 0.0)));\r\n    float flashBright = flashActive * exp(-flashT * 8.0) * step(flashT, 0.5);\r\n    // Rumble: oscillating dim glow after flash\r\n    float rumble = flashActive * exp(-flashT * 1.5) * abs(sin(flashT * 18.0)) * 0.06 * step(0.08, flashT);\r\n\r\n    float flashActive2 = step(0.985, hash12(vec2(flashSeed2, 1.0)));\r\n    float flashBright2 = flashActive2 * exp(-flashT2 * 10.0) * step(flashT2, 0.4);\r\n    float rumble2 = flashActive2 * exp(-flashT2 * 1.2) * abs(sin(flashT2 * 14.0)) * 0.05 * step(0.06, flashT2);\r\n\r\n    // Lightning bolt channels\r\n    float bolt1 = 0.0;\r\n    float bolt2 = 0.0;\r\n    if (flashActive > 0.5) {\r\n        bolt1 = lightningChannel(uv, flashSeed * 3.7, u_time) * flashBright;\r\n    }\r\n    if (flashActive2 > 0.5) {\r\n        bolt2 = lightningChannel(uv, flashSeed2 * 5.3 + 1.1, u_time) * flashBright2;\r\n    }\r\n\r\n    // Cloud illumination from lightning (glow from within)\r\n    float cloudGlow = (flashBright + flashBright2) * (layer2 * 0.5 + layer3 * 0.3) * 0.35;\r\n\r\n    // ── Rain layers (3 depths with different angles and speeds) ──────────\r\n    float rain1 = rainLayer(uv, 0.9, -0.25, 15.0, u_time, 0.0);  // Far\r\n    float rain2 = rainLayer(uv, 1.3, -0.30, 12.0, u_time, 1.0);  // Mid\r\n    float rain3 = rainLayer(uv, 1.8, -0.35,  8.0, u_time, 2.0);  // Near (heavier)\r\n\r\n    vec3 rainFar  = rainColor * rain1 * 0.08;\r\n    vec3 rainMid  = rainColor * rain2 * 0.12;\r\n    vec3 rainNear = rainColor * rain3 * 0.18;\r\n\r\n    // ── Compose final color ───────────────────────────────────────────────\r\n    vec3 color = cloudColor;\r\n    // Lightning bolt and glow\r\n    color += lightningWht * (bolt1 + bolt2);\r\n    color += lightningBlu * cloudGlow;\r\n    color += lightningWht * (rumble + rumble2);\r\n    // Rain at different depths\r\n    color += rainFar;\r\n    color += rainMid;\r\n    color += rainNear;\r\n\r\n    // ── Subtle vignette to darken storm edges ─────────────────────────────\r\n    vec2 cv = uv * 2.0 - 1.0;\r\n    float vignette = 1.0 - smoothstep(0.6, 1.4, length(cv * vec2(1.0, 0.8)));\r\n    color *= 0.85 + 0.15 * vignette;\r\n\r\n    color *= u_intensity;\r\n    gl_FragColor = vec4(color, 1.0);\r\n}";

window.SHADER_SOURCES["water-shader.glsl"] = "precision highp float;\r\nuniform vec2 u_resolution;\r\nuniform float u_time;\r\nuniform float u_intensity;\r\n\r\n// ============================================================================\r\n// OCEAN SHADER - Underwater world with volumetric light, bioluminescence\r\n// Features: Light shafts, marine snow, surface ripples, biolumin, depth fog\r\n// ============================================================================\r\n\r\nfloat hash12(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * 0.1031);\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.x + p3.y) * p3.z);\r\n}\r\n\r\nvec2 hash22(vec2 p) {\r\n    vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));\r\n    p3 += dot(p3, p3.yzx + 33.33);\r\n    return fract((p3.xx + p3.yz) * p3.zy);\r\n}\r\n\r\nvec2 quintic(vec2 t) {\r\n    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\r\n}\r\n\r\nfloat valueNoise(vec2 p) {\r\n    vec2 i = floor(p);\r\n    vec2 f = quintic(fract(p));\r\n    float a = hash12(i);\r\n    float b = hash12(i + vec2(1.0, 0.0));\r\n    float c = hash12(i + vec2(0.0, 1.0));\r\n    float d = hash12(i + vec2(1.0, 1.0));\r\n    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);\r\n}\r\n\r\nfloat fbm(vec2 p, int octaves) {\r\n    float value = 0.0;\r\n    float amplitude = 0.5;\r\n    for (int i = 0; i < 8; i++) {\r\n        if (i >= octaves) break;\r\n        value += amplitude * valueNoise(p);\r\n        p *= 2.0;\r\n        amplitude *= 0.5;\r\n    }\r\n    return value;\r\n}\r\n\r\n// Voronoi cell distance\r\nfloat voronoi(vec2 p, float time) {\r\n    vec2 n = floor(p);\r\n    vec2 f = fract(p);\r\n    float d = 1.0;\r\n    for (int j = -1; j <= 1; j++) {\r\n        for (int i = -1; i <= 1; i++) {\r\n            vec2 g = vec2(float(i), float(j));\r\n            vec2 o = hash22(n + g);\r\n            o = 0.5 + 0.5 * sin(time * 0.35 + 6.2831 * o);\r\n            float dist = length(g + o - f);\r\n            if (dist < d) d = dist;\r\n        }\r\n    }\r\n    return d;\r\n}\r\n\r\n// Volumetric light shaft from surface above\r\nfloat lightShaft(vec2 uv, float shaftX, float width, float waviness, float time) {\r\n    // Shaft wiggles horizontally from wave action at surface\r\n    float wiggle = sin(uv.y * 3.0 + time * 0.3 + shaftX * 6.28) * waviness;\r\n    wiggle += sin(uv.y * 7.0 - time * 0.18) * waviness * 0.4;\r\n    float dist = abs(uv.x - shaftX + wiggle);\r\n    // Shaft narrows with depth (less focused deeper)\r\n    float widthAtDepth = width + (1.0 - uv.y) * 0.04;\r\n    float shaft = smoothstep(widthAtDepth, widthAtDepth * 0.2, dist);\r\n    // Attenuate with depth — less light penetrates deep\r\n    shaft *= exp(-(1.0 - uv.y) * 2.5);\r\n    // Shaft intensity modulated by surface waves (passing clouds / ripples)\r\n    float waveMod = fbm(vec2(shaftX * 4.0 + time * 0.12, time * 0.08), 3);\r\n    shaft *= 0.5 + 0.5 * waveMod;\r\n    return shaft;\r\n}\r\n\r\n// Surface ripple distortion pattern (viewed from below)\r\nfloat surfaceRipple(vec2 uv, float time) {\r\n    // Concentric ring patterns for ripples\r\n    float r1 = fbm(uv * 8.0 + time * 0.25, 4);\r\n    float r2 = fbm(uv * 12.0 - time * 0.18, 3);\r\n    float ripple = sin((r1 + r2 * 0.5) * 12.56);\r\n    ripple = ripple * 0.5 + 0.5;\r\n    ripple = pow(ripple, 3.0);\r\n    return ripple;\r\n}\r\n\r\n// Bioluminescent glow spot\r\nfloat bioLumin(vec2 uv, vec2 center, float radius, float pulse) {\r\n    float d = length(uv - center);\r\n    float glow = exp(-d * d / (radius * radius * 2.0));\r\n    return glow * pulse;\r\n}\r\n\r\nvoid main() {\r\n    vec2 uv = gl_FragCoord.xy / u_resolution.xy;\r\n    float aspect = u_resolution.x / u_resolution.y;\r\n    vec2 c = uv * 2.0 - 1.0;\r\n    c.x *= aspect;\r\n\r\n    // ── Ocean color palette ───────────────────────────────────────────────\r\n    vec3 deepOcean   = vec3(0.0,  0.05,  0.12);\r\n    vec3 midOcean    = vec3(0.02, 0.10,  0.22);\r\n    vec3 shallowBlue = vec3(0.06, 0.18,  0.35);\r\n    vec3 surfaceBlue = vec3(0.12, 0.26,  0.48);\r\n    vec3 lightBeam   = vec3(0.10, 0.22,  0.40);\r\n    vec3 causticBlue = vec3(0.15, 0.32,  0.50);\r\n    vec3 foamWhite   = vec3(0.55, 0.65,  0.75);\r\n    vec3 bioGreen    = vec3(0.02, 0.45,  0.38);\r\n    vec3 bioBlue     = vec3(0.02, 0.35,  0.58);\r\n    vec3 snowWhite   = vec3(0.70, 0.75,  0.80);\r\n\r\n    // ── Depth fog effect ──────────────────────────────────────────────────\r\n    // UV.y = 1 is surface, UV.y = 0 is deep\r\n    float depth = 1.0 - uv.y;\r\n    float fogAmount = 1.0 - exp(-depth * 2.0);\r\n    vec3 base = mix(shallowBlue, deepOcean, fogAmount);\r\n\r\n    // ── Subtle current-driven FBM for ambient water movement ─────────────\r\n    // Current flows leftward (from right to left)\r\n    vec2 currentUV = uv + vec2(-u_time * 0.015, 0.0);\r\n    float ambient1 = fbm(currentUV * 3.0, 4);\r\n    float ambient2 = fbm(currentUV * 5.5 + 2.3, 3);\r\n    base += midOcean * ambient1 * 0.04;\r\n    base += shallowBlue * ambient2 * 0.02;\r\n\r\n    // ── Volumetric light shafts from above ────────────────────────────────\r\n    float shaft1 = lightShaft(uv, 0.30, 0.025, 0.015, u_time);\r\n    float shaft2 = lightShaft(uv, 0.52, 0.018, 0.012, u_time + 1.3);\r\n    float shaft3 = lightShaft(uv, 0.68, 0.030, 0.018, u_time + 2.7);\r\n    float shaft4 = lightShaft(uv, 0.82, 0.015, 0.010, u_time + 0.8);\r\n    float shafts = shaft1 + shaft2 * 0.7 + shaft3 * 0.85 + shaft4 * 0.5;\r\n    // Only in upper portion (light doesn't penetrate far)\r\n    shafts *= smoothstep(0.0, 0.7, uv.y);\r\n    vec3 shaftColor = lightBeam * shafts * 0.35;\r\n\r\n    // ── Caustic light patterns ─────────────────────────────────────────────\r\n    float v1 = voronoi(uv * 5.5 + vec2(u_time * 0.06, u_time * 0.03), u_time);\r\n    float v2 = voronoi(uv * 8.0  - vec2(u_time * 0.05, u_time * 0.04), u_time);\r\n    float v3 = voronoi(uv * 12.0 + vec2(u_time * 0.03, -u_time * 0.05), u_time);\r\n    float caustic = pow(1.0 - (v1 * 0.45 + v2 * 0.35 + v3 * 0.20), 4.0);\r\n    caustic = smoothstep(0.25, 0.85, caustic);\r\n    // Caustics only where light shafts reach\r\n    caustic *= smoothstep(0.0, 0.6, uv.y) * 0.15;\r\n    vec3 causticColor = causticBlue * caustic;\r\n\r\n    // ── Surface ripple / wave pattern visible from below ──────────────────\r\n    float ripple = surfaceRipple(uv, u_time);\r\n    // Only visible near surface\r\n    float rippleMask = smoothstep(0.75, 1.0, uv.y);\r\n    vec3 rippleColor = surfaceBlue * ripple * rippleMask * 0.20;\r\n    // Foam at very surface\r\n    float foamNoise = fbm(vec2(uv.x * 18.0 + u_time * 0.25, uv.y * 8.0), 3);\r\n    float foam = smoothstep(0.93, 1.0, uv.y) * foamNoise * 0.25;\r\n    vec3 foamColor = foamWhite * foam;\r\n\r\n    // ── Marine snow: tiny organic particles drifting with current ────────\r\n    vec3 snowColor = vec3(0.0);\r\n    for (int i = 0; i < 40; i++) {\r\n        float fi = float(i);\r\n        vec2 seed = vec2(fi * 0.113, fi * 0.257);\r\n        float speed = 0.02 + hash12(seed) * 0.025;\r\n        float xDrift = hash12(seed + 5.1) * 0.008;  // Leftward current\r\n        float sway = sin(u_time * 0.15 + fi * 1.23) * 0.008;\r\n        float t = mod(u_time * speed + hash12(seed + 3.0) * 8.0, 1.2) / 1.2;\r\n        // Drift downward (snow falls) with current influence\r\n        vec2 pos = vec2(\r\n            fract(hash12(seed + 1.0) + sway - u_time * xDrift),\r\n            1.0 - t\r\n        );\r\n        float sz = 0.002 + hash12(seed + 7.0) * 0.004;\r\n        float fade = smoothstep(0.0, 0.08, t) * smoothstep(1.0, 0.9, t);\r\n        float mote = smoothstep(sz, sz * 0.1, length(uv - pos)) * fade;\r\n        // Depth-based visibility: more particles mid-water, few near surface\r\n        float depthVis = smoothstep(0.9, 0.7, uv.y) * smoothstep(0.05, 0.2, uv.y);\r\n        snowColor += snowWhite * mote * depthVis * 0.06;\r\n    }\r\n\r\n    // ── Depth fog on particles (distance fade) ────────────────────────────\r\n    // Already handled by depth gradient in base, but enhance further\r\n    vec3 depthFog = deepOcean * fogAmount * 0.3;\r\n\r\n    // ── Bioluminescent spots: rare, subtle, blue-green ────────────────────\r\n    vec3 bioColor = vec3(0.0);\r\n    // 5 bioluminescent organisms, slowly drifting\r\n    for (int b = 0; b < 5; b++) {\r\n        float fb = float(b);\r\n        vec2 bSeed = vec2(fb * 0.318, fb * 0.541);\r\n        float bSpeed = 0.008 + hash12(bSeed) * 0.006;\r\n        float bPhase = hash12(bSeed + 2.0) * 6.28;\r\n        // Drift slowly with slight oscillation\r\n        float bx = fract(hash12(bSeed + 1.0) + u_time * bSpeed * 0.3 + sin(u_time * 0.1 + bPhase) * 0.02);\r\n        float by = fract(hash12(bSeed + 3.0) + u_time * bSpeed + cos(u_time * 0.08 + bPhase) * 0.015);\r\n        vec2 bPos = vec2(bx, by);\r\n        // Only in deeper water (below surface)\r\n        float depthMask = smoothstep(0.7, 0.4, by);\r\n        // Pulse gently\r\n        float bPulse = 0.3 + 0.7 * pow(sin(u_time * 0.4 + bPhase) * 0.5 + 0.5, 2.0);\r\n        float bRadius = 0.015 + hash12(bSeed + 4.0) * 0.025;\r\n        float glow = bioLumin(uv, bPos, bRadius, bPulse) * depthMask;\r\n        // Mix between blue and green bioluminescence\r\n        vec3 bioHue = mix(bioBlue, bioGreen, hash12(bSeed + 6.0));\r\n        bioColor += bioHue * glow * 0.12;\r\n    }\r\n\r\n    // ── Current flow visualization (through particle drift direction) ──────\r\n    // Already handled via snow particles + shaft wiggle, but add subtle streak\r\n    float currentFlow = fbm(vec2(uv.x * 6.0 - u_time * 0.08, uv.y * 4.0), 3);\r\n    float currentFlow2 = fbm(vec2(uv.x * 10.0 - u_time * 0.06, uv.y * 6.0 + 2.0), 2);\r\n    vec3 currentColor = midOcean * currentFlow * currentFlow2 * 0.025;\r\n\r\n    // ── Ambient noise for water texture ───────────────────────────────────\r\n    float ambient = fbm(uv * 9.0 + u_time * 0.025, 4);\r\n    vec3 ambientColor = midOcean * ambient * 0.03;\r\n\r\n    // ── Compose all layers ────────────────────────────────────────────────\r\n    vec3 color = base;\r\n    color += depthFog;\r\n    color += shaftColor;\r\n    color += causticColor;\r\n    color += rippleColor;\r\n    color += foamColor;\r\n    color += snowColor;\r\n    color += bioColor;\r\n    color += currentColor;\r\n    color += ambientColor;\r\n    color *= u_intensity;\r\n\r\n    gl_FragColor = vec4(color, 1.0);\r\n}";
